import type { Node, Edge } from "@xyflow/react";
import type {
  DiagramData,
  Service,
  Consumer,
  Saga,
  InboundRoute,
  OutboundRoute,
  Transport,
  TopologyEntity,
  TopologyLink,
  MessageType,
} from "../types/diagram";
import type { CompactNodeData } from "../components/nodes/CompactNode";
import type { SimpleRouteNodeData } from "../components/nodes/SimpleRouteNode";
import type { SimpleGroupLabelData } from "../components/nodes/SimpleGroupLabel";
import type { SummaryServiceNodeData } from "../components/nodes/SummaryServiceNode";
import type { SummaryTransportNodeData } from "../components/nodes/SummaryTransportNode";

// =============================================================================
// TYPES
// =============================================================================

export interface FlowElements {
  nodes: Node[];
  edges: Edge[];
}

interface FlowBuilder {
  nodes: Node[];
  edges: Edge[];
}

type LayerConstraint = "FIRST" | "LAST";

// =============================================================================
// CONSTANTS
// =============================================================================

const LAYOUT = {
  GROUP_PADDING: 25,
  TITLE_HEIGHT: 40,
} as const;

const STYLES = {
  edge: { stroke: "#6e7681", strokeWidth: 1 },
  serviceGroup: {
    backgroundColor: "rgba(22, 27, 34, 0.3)",
    borderRadius: "8px",
    border: "1px solid #30363d",
  },
  inboundGroup: {
    backgroundColor: "rgba(88, 166, 255, 0.05)",
    borderRadius: "6px",
    border: "1px solid rgba(88, 166, 255, 0.3)",
  },
  outboundGroup: {
    backgroundColor: "rgba(219, 97, 162, 0.05)",
    borderRadius: "6px",
    border: "1px solid rgba(219, 97, 162, 0.3)",
  },
  transportGroup: {
    backgroundColor: "rgba(163, 113, 247, 0.05)",
    borderRadius: "8px",
    border: "1px solid #a371f7",
  },
} as const;

const NODE_IDS = {
  SERVICE_GROUP: "service-group",
  SERVICE_TITLE: "service-title",
  INBOUND_SUBFLOW: "inbound-subflow",
  OUTBOUND_SUBFLOW: "outbound-subflow",
} as const;

// =============================================================================
// MAIN ENTRY POINT
// =============================================================================

/**
 * Transforms diagram data into React Flow nodes and edges.
 * This is transport-agnostic - it works with any transport type.
 *
 * Data structure:
 * - services[]: application config (host, messageTypes, consumers, routes, sagas)
 * - transports[]: infrastructure config (endpoints, topology)
 */
export function diagramToFlow(data: DiagramData): FlowElements {
  const builder: FlowBuilder = { nodes: [], edges: [] };

  // Build service groups (one per service)
  data.services.forEach((service, idx) => {
    buildServiceGroup(builder, service, idx, data.transports);
  });

  // Build transport groups
  buildTransportGroups(builder, data);

  // Build summary nodes and summary edges for semantic zoom
  buildSummaryNodes(builder, data);

  return { nodes: builder.nodes, edges: builder.edges };
}

// =============================================================================
// SERVICE GROUP
// =============================================================================
function buildServiceGroup(
  builder: FlowBuilder,
  service: Service,
  serviceIndex: number,
  transports: Transport[],
): void {
  const sagaConsumerNames = new Set(service.sagas.map((s) => s.consumerName));
  const suffix = serviceIndex > 0 ? `-${serviceIndex}` : "";
  const serviceGroupId = `${NODE_IDS.SERVICE_GROUP}${suffix}`;
  const serviceTitleId = `${NODE_IDS.SERVICE_TITLE}${suffix}`;
  const inboundId = `${NODE_IDS.INBOUND_SUBFLOW}${suffix}`;
  const outboundId = `${NODE_IDS.OUTBOUND_SUBFLOW}${suffix}`;

  // Main service container
  addGroupNode(builder, {
    id: serviceGroupId,
    position: { x: 20, y: 20 },
    size: { width: 600, height: 700 },
    style: STYLES.serviceGroup,
    label: service.host.serviceName,
  });

  addGroupLabel(builder, {
    id: serviceTitleId,
    parentId: serviceGroupId,
    position: { x: LAYOUT.GROUP_PADDING, y: 0 },
    label: service.host.serviceName,
    type: "service",
  });

  buildInboundSubflow(
    builder,
    service,
    sagaConsumerNames,
    serviceGroupId,
    inboundId,
    transports,
    suffix,
  );
  buildOutboundSubflow(builder, service, serviceGroupId, outboundId, transports, suffix);
}

// =============================================================================
// INBOUND SUBFLOW
// =============================================================================

function buildInboundSubflow(
  builder: FlowBuilder,
  service: Service,
  sagaConsumerNames: Set<string>,
  serviceGroupId: string,
  parentId: string,
  transports: Transport[],
  suffix: string,
): void {
  // Inbound container (minimal initial size; resized by elkLayout to fit children)
  addGroupNode(builder, {
    id: parentId,
    parentId: serviceGroupId,
    position: { x: LAYOUT.GROUP_PADDING, y: LAYOUT.TITLE_HEIGHT + 15 },
    size: { width: 300, height: 60 },
    style: STYLES.inboundGroup,
    label: "Inbound",
  });

  addGroupLabel(builder, {
    id: `${parentId}-title`,
    parentId,
    position: { x: LAYOUT.GROUP_PADDING, y: 0 },
    label: "Inbound",
    type: "service",
  });

  // LEFT column: Consumers and Sagas (suffixed IDs to avoid collisions across services)
  const regularConsumers = service.consumers.filter(
    (c) => !sagaConsumerNames.has(c.name),
  );
  regularConsumers.forEach((consumer) =>
    addConsumerNode(builder, consumer, parentId, suffix),
  );
  service.sagas.forEach((saga) => addSagaNode(builder, saga, parentId, suffix));

  // MIDDLE column: Routes (suffixed IDs to avoid collisions across services)
  service.routes.inbound.forEach((route, idx) => {
    addRouteNode(builder, {
      id: `route-inbound${suffix}-${idx}`,
      parentId,
      kind: route.kind,
      direction: "inbound",
      messageTypeIdentity: route.messageTypeIdentity,
      consumerName: route.consumerName,
      endpointName: route.endpoint.name,
    });
  });

  // RIGHT column: Only receive endpoints referenced by this service's inbound routes
  const relevantEndpoints = new Set(
    service.routes.inbound.map((r) => r.endpoint.name),
  );
  const addedReceiveEndpoints = new Set<string>();
  transports.forEach((transport) => {
    transport.receiveEndpoints.forEach((endpoint) => {
      if (
        relevantEndpoints.has(endpoint.name) &&
        !addedReceiveEndpoints.has(endpoint.name)
      ) {
        addedReceiveEndpoints.add(endpoint.name);
        addEndpointNode(builder, {
          id: `receive-${endpoint.name}`,
          parentId,
          name: endpoint.name,
          address: endpoint.address,
          transportName: transport.name,
          subType: "receive",
          layer: "LAST",
        });
      }
    });
  });

  // Edges: Consumer -> Route -> Endpoint (suffix used for both route and consumer IDs)
  buildInboundEdges(
    builder,
    service.routes.inbound,
    service.sagas,
    sagaConsumerNames,
    suffix,
  );

}

function buildInboundEdges(
  builder: FlowBuilder,
  routes: InboundRoute[],
  sagas: Saga[],
  sagaConsumerNames: Set<string>,
  suffix: string,
): void {
  routes.forEach((route, idx) => {
    const routeId = `route-inbound${suffix}-${idx}`;
    const consumerId = resolveConsumerId(
      route.consumerName,
      sagas,
      sagaConsumerNames,
      suffix,
    );

    addEdge(builder, {
      id: `edge-consumer-route${suffix}-${idx}`,
      target: consumerId,
      source: routeId,
      targetHandle: "right",
      sourceHandle: "left-source",
      markerEnd: true,
    });

    addEdge(builder, {
      id: `edge-route-recv${suffix}-${idx}`,
      source: `receive-${route.endpoint.name}`,
      target: routeId,
      targetHandle: "right",
      sourceHandle: "left-source",
      markerEnd: true,
    });
  });
}

function resolveConsumerId(
  consumerName: string,
  sagas: Saga[],
  sagaConsumerNames: Set<string>,
  suffix: string,
): string {
  if (sagaConsumerNames.has(consumerName)) {
    const saga = sagas.find((s) => s.consumerName === consumerName);
    if (saga) {
      return `saga${suffix}-${saga.name}`;
    }
  }
  return `consumer${suffix}-${consumerName}`;
}

// =============================================================================
// OUTBOUND SUBFLOW
// =============================================================================

function buildOutboundSubflow(
  builder: FlowBuilder,
  service: Service,
  serviceGroupId: string,
  parentId: string,
  transports: Transport[],
  suffix: string,
): void {
  // Outbound container (minimal initial size; resized by elkLayout to fit children)
  addGroupNode(builder, {
    id: parentId,
    parentId: serviceGroupId,
    position: { x: LAYOUT.GROUP_PADDING, y: 350 },
    size: { width: 300, height: 60 },
    style: STYLES.outboundGroup,
    label: "Outbound",
  });

  addGroupLabel(builder, {
    id: `${parentId}-title`,
    parentId,
    position: { x: LAYOUT.GROUP_PADDING, y: 0 },
    label: "Outbound",
    type: "service",
  });

  // Build a lookup for message identity to index
  const messageIdentityToIdx = new Map<string, number>();
  service.messageTypes.forEach((mt, idx) => {
    messageIdentityToIdx.set(mt.identity, idx);
  });

  // LEFT column: Only message types referenced by outbound routes
  const routedMessageIdentities = new Set(
    service.routes.outbound.map((r) => r.messageTypeIdentity),
  );
  service.messageTypes.forEach((messageType, idx) => {
    if (!routedMessageIdentities.has(messageType.identity)) return;
    addMessageNode(builder, {
      id: `msgtype${suffix}-${idx}`,
      parentId,
      identity: messageType.identity,
      messageType,
    });
  });

  // MIDDLE column: Routes (suffixed IDs)
  service.routes.outbound.forEach((route, idx) => {
    addRouteNode(builder, {
      id: `route-outbound${suffix}-${idx}`,
      parentId,
      kind: route.kind,
      direction: "outbound",
      messageTypeIdentity: route.messageTypeIdentity,
      endpointName: route.endpoint.name,
    });
  });

  // RIGHT column: Only dispatch endpoints referenced by this service's outbound routes
  const relevantDispatchEndpoints = new Set(
    service.routes.outbound.map((r) => r.endpoint.name),
  );
  const addedDispatchEndpoints = new Set<string>();
  transports.forEach((transport) => {
    transport.dispatchEndpoints.forEach((endpoint) => {
      if (
        relevantDispatchEndpoints.has(endpoint.name) &&
        !addedDispatchEndpoints.has(endpoint.name)
      ) {
        addedDispatchEndpoints.add(endpoint.name);
        addEndpointNode(builder, {
          id: `dispatch-${endpoint.name}`,
          parentId,
          name: endpoint.name,
          address: endpoint.address,
          transportName: transport.name,
          subType: "dispatch",
          layer: "LAST",
        });
      }
    });
  });

  // Edges: Message -> Route -> Endpoint
  buildOutboundEdges(builder, service.routes.outbound, messageIdentityToIdx, suffix);
}

function buildOutboundEdges(
  builder: FlowBuilder,
  routes: OutboundRoute[],
  messageIdentityToIdx: Map<string, number>,
  suffix: string,
): void {
  routes.forEach((route, idx) => {
    const routeId = `route-outbound${suffix}-${idx}`;
    const msgIdx = messageIdentityToIdx.get(route.messageTypeIdentity);

    // Only create edge if message type exists
    if (msgIdx !== undefined) {
      addEdge(builder, {
        id: `edge-msg-route${suffix}-${idx}`,
        source: `msgtype${suffix}-${msgIdx}`,
        target: routeId,
        sourceHandle: "right-source",
        targetHandle: "left",
        markerEnd: true,
      });
    }

    addEdge(builder, {
      id: `edge-route-dispatch${suffix}-${idx}`,
      source: routeId,
      target: `dispatch-${route.endpoint.name}`,
      sourceHandle: "right-source",
      targetHandle: "left",
      markerEnd: true,
    });
  });
}

// =============================================================================
// TRANSPORT GROUPS
// =============================================================================

function buildTransportGroups(builder: FlowBuilder, data: DiagramData): void {
  // Collect all routes from all services
  const allOutboundRoutes: OutboundRoute[] = [];
  const allInboundRoutes: InboundRoute[] = [];
  data.services.forEach((service) => {
    allOutboundRoutes.push(...service.routes.outbound);
    allInboundRoutes.push(...service.routes.inbound);
  });

  data.transports.forEach((transport) => {
    buildTransportGroup(
      builder,
      transport,
      allOutboundRoutes,
      allInboundRoutes,
    );
  });
}

function buildTransportGroup(
  builder: FlowBuilder,
  transport: Transport,
  outboundRoutes: OutboundRoute[],
  inboundRoutes: InboundRoute[],
): void {
  const groupId = `transport-${transport.name}`;

  // Transport container
  addGroupNode(builder, {
    id: groupId,
    position: { x: 750, y: 50 },
    size: { width: 500, height: 400 },
    style: STYLES.transportGroup,
    label: transport.name,
  });

  addGroupLabel(builder, {
    id: `${groupId}-title`,
    parentId: groupId,
    position: { x: LAYOUT.GROUP_PADDING, y: 0 },
    label: transport.name,
    type: "transport",
  });

  // Add topology entities - use flow property for layer constraints
  addTopologyEntities(
    builder,
    transport.topology.entities,
    transport.topology.links,
    groupId,
  );

  // Add internal topology links as binding nodes with directional arrows
  addTopologyLinks(builder, transport.topology.links, transport.name, groupId);

  // Add cross-group edges connecting service endpoints to transport entities
  addDispatchToTransportEdges(builder, outboundRoutes, transport);
  addTransportToReceiveEdges(builder, inboundRoutes, transport);
}

/**
 * Adds topology entities to the transport group.
 * Uses the entity's `flow` property to determine layer position:
 * - "inbound" entities go on the LEFT (receive messages from dispatch endpoints)
 * - "outbound" entities go on the RIGHT (send messages to receive endpoints)
 */
function addTopologyEntities(
  builder: FlowBuilder,
  entities: TopologyEntity[],
  links: TopologyLink[],
  groupId: string,
): void {
  const nodesWithSource = new Set(
    links.flatMap((x) =>
      x.direction === "bidirectional"
        ? [x.source, x.target]
        : x.direction === "forward"
          ? [x.target]
          : [x.source],
    ),
  );
  entities.forEach((entity) => {
    const nodeId = buildEntityNodeId(entity);
    // Use flow property: inbound = FIRST (left), outbound = LAST (right)
    const layer: LayerConstraint | undefined =
      entity.flow === "outbound"
        ? "LAST"
        : nodesWithSource.has(entity.address)
          ? undefined
          : "FIRST";

    builder.nodes.push({
      id: nodeId,
      type: "compact",
      position: { x: 0, y: 0 },
      data: {
        label: truncateLabel(entity.name, 30),
        nodeType: "entity",
        entityKind: entity.kind,
        elkLayer: layer,
        fullData: {
          name: entity.name,
          kind: entity.kind,
          address: entity.address,
          flow: entity.flow,
          properties: entity.properties,
        },
      } satisfies CompactNodeData,
      parentId: groupId,
      extent: "parent",
    });
  });
}

/**
 * Adds topology links as binding nodes with directional edges.
 * The `direction` property on links determines arrow direction:
 * - "forward": source → target (default)
 * - "reverse": target → source
 * - "bidirectional": both directions
 */
function addTopologyLinks(
  builder: FlowBuilder,
  links: TopologyLink[],
  transportName: string,
  groupId: string,
): void {
  links.forEach((link, idx) => {
    const sourceId = addressToEntityId(link.source);
    const targetId = addressToEntityId(link.target);

    if (!sourceId || !targetId) return;
    if (!nodeExists(builder, sourceId) || !nodeExists(builder, targetId))
      return;

    const bindingNodeId = `binding-${transportName}-${idx}`;

    // Create a binding node (similar to route nodes)
    builder.nodes.push({
      id: bindingNodeId,
      type: "route",
      position: { x: 0, y: 0 },
      data: {
        label: link.kind,
        kind: link.kind,
        nodeType: "binding",
        fullData: {
          kind: link.kind,
          address: link.address,
          direction: link.direction,
          source: link.source,
          target: link.target,
          properties: link.properties,
        },
      } satisfies SimpleRouteNodeData,
      parentId: groupId,
      extent: "parent",
    });

    // Create directional edges based on link direction
    addDirectionalBindingEdges(
      builder,
      bindingNodeId,
      sourceId,
      targetId,
      link.direction,
    );
  });
}

function addDispatchToTransportEdges(
  builder: FlowBuilder,
  _routes: OutboundRoute[],
  transport: Transport,
): void {
  // Connect ALL dispatch endpoints to their destination entities
  transport.dispatchEndpoints.forEach((dispatchEndpoint) => {
    const destId = addressToEntityId(dispatchEndpoint.destination.address);
    if (!destId || !nodeExists(builder, destId)) return;

    // Check if the dispatch endpoint node exists
    if (!nodeExists(builder, `dispatch-${dispatchEndpoint.name}`)) return;

    addEdge(builder, {
      id: `edge-dispatch-entity-${dispatchEndpoint.name}`,
      source: `dispatch-${dispatchEndpoint.name}`,
      target: destId,
      sourceHandle: "right-source",
      targetHandle: "left",
      markerEnd: true,
    });
  });
}

function addTransportToReceiveEdges(
  builder: FlowBuilder,
  _routes: InboundRoute[],
  transport: Transport,
): void {
  // Connect ALL receive endpoints from their source entities
  transport.receiveEndpoints.forEach((receiveEndpoint) => {
    const sourceId = addressToEntityId(receiveEndpoint.source.address);
    if (!sourceId || !nodeExists(builder, sourceId)) return;

    // Check if the receive endpoint node exists
    if (!nodeExists(builder, `receive-${receiveEndpoint.name}`)) return;

    addEdge(builder, {
      id: `edge-entity-recv-${receiveEndpoint.name}`,
      source: sourceId,
      target: `receive-${receiveEndpoint.name}`,
      sourceHandle: "right-source",
      targetHandle: "right",
      markerEnd: true,
    });
  });
}

// =============================================================================
// NODE FACTORIES
// =============================================================================

interface GroupNodeOptions {
  id: string;
  parentId?: string;
  position: { x: number; y: number };
  size: { width: number; height: number };
  style: Record<string, string>;
  label: string;
}

function addGroupNode(builder: FlowBuilder, options: GroupNodeOptions): void {
  builder.nodes.push({
    id: options.id,
    type: "group",
    position: options.position,
    style: {
      ...options.style,
      width: options.size.width,
      height: options.size.height,
    },
    data: { label: options.label },
    ...(options.parentId && { parentId: options.parentId, extent: "parent" }),
  });
}

interface GroupLabelOptions {
  id: string;
  parentId: string;
  position: { x: number; y: number };
  label: string;
  type: "service" | "transport";
}

function addGroupLabel(builder: FlowBuilder, options: GroupLabelOptions): void {
  builder.nodes.push({
    id: options.id,
    type: "groupLabel",
    position: options.position,
    data: {
      label: options.label,
      type: options.type,
    } satisfies SimpleGroupLabelData,
    parentId: options.parentId,
    extent: "parent",
    draggable: false,
  });
}

function addConsumerNode(
  builder: FlowBuilder,
  consumer: Consumer,
  parentId: string,
  suffix: string,
): void {
  builder.nodes.push({
    id: `consumer${suffix}-${consumer.name}`,
    type: "compact",
    position: { x: 0, y: 0 },
    data: {
      label: getShortName(consumer.name),
      nodeType: "consumer",
      isBatch: consumer.isBatch || false,
      elkLayer: "FIRST",
      fullData: {
        name: consumer.name,
        identityType: consumer.identityType,
        identityTypeFullName: consumer.identityTypeFullName,
        isBatch: consumer.isBatch || false,
      },
    } satisfies CompactNodeData,
    parentId,
    extent: "parent",
  });
}

function addSagaNode(builder: FlowBuilder, saga: Saga, parentId: string, suffix: string): void {
  builder.nodes.push({
    id: `saga${suffix}-${saga.name}`,
    type: "compact",
    position: { x: 0, y: 0 },
    data: {
      label: getShortName(saga.name),
      nodeType: "saga",
      elkLayer: "FIRST",
      fullData: {
        name: saga.name,
        stateType: saga.stateType,
        stateTypeFullName: saga.stateTypeFullName,
        consumerName: saga.consumerName,
        states: saga.states,
      },
    } satisfies CompactNodeData,
    parentId,
    extent: "parent",
  });
}

interface RouteNodeOptions {
  id: string;
  parentId: string;
  kind: string;
  direction: "inbound" | "outbound";
  messageTypeIdentity?: string;
  consumerName?: string;
  endpointName?: string;
}

function addRouteNode(builder: FlowBuilder, options: RouteNodeOptions): void {
  builder.nodes.push({
    id: options.id,
    type: "route",
    position: { x: 0, y: 0 },
    data: {
      label: options.kind,
      kind: options.kind,
      direction: options.direction,
      nodeType: "route",
      fullData: {
        kind: options.kind,
        direction: options.direction,
        messageTypeIdentity: options.messageTypeIdentity,
        consumerName: options.consumerName,
        endpointName: options.endpointName,
      },
    } satisfies SimpleRouteNodeData,
    parentId: options.parentId,
    extent: "parent",
  });
}

interface EndpointNodeOptions {
  id: string;
  parentId: string;
  name: string;
  address: string;
  transportName: string;
  subType: "receive" | "dispatch";
  layer: LayerConstraint;
}

function addEndpointNode(
  builder: FlowBuilder,
  options: EndpointNodeOptions,
): void {
  builder.nodes.push({
    id: options.id,
    type: "compact",
    position: { x: 0, y: 0 },
    data: {
      label: getShortName(options.name),
      nodeType: "endpoint",
      subType: options.subType,
      elkLayer: options.layer,
      fullData: {
        name: options.name,
        address: options.address,
        transportName: options.transportName,
        kind: options.subType,
      },
    } satisfies CompactNodeData,
    parentId: options.parentId,
    extent: "parent",
  });
}

interface MessageNodeOptions {
  id: string;
  parentId: string;
  identity: string;
  messageType?: MessageType;
}

function addMessageNode(
  builder: FlowBuilder,
  options: MessageNodeOptions,
): void {
  builder.nodes.push({
    id: options.id,
    type: "compact",
    position: { x: 0, y: 0 },
    data: {
      label: options.messageType?.runtimeType || "Unknown",
      nodeType: "message",
      elkLayer: "FIRST",
      fullData: {
        name: options.messageType?.runtimeType,
        identity: options.identity,
        runtimeType: options.messageType?.runtimeType,
        runtimeTypeFullName: options.messageType?.runtimeTypeFullName,
        isInterface: options.messageType?.isInterface,
        isInternal: options.messageType?.isInternal,
      },
    } satisfies CompactNodeData,
    parentId: options.parentId,
    extent: "parent",
  });
}

// =============================================================================
// EDGE FACTORY
// =============================================================================

interface EdgeOptions {
  id: string;
  source: string;
  target: string;
  sourceHandle: string;
  targetHandle: string;
  /** Show arrow at target (end) */
  animated?: boolean;
  /** Arrow marker type */
  markerEnd?: boolean;
}

/**
 * Creates an edge between two nodes.
 *
 * Uses React Flow's built-in smoothstep edge for service-group edges.
 * Transport-internal edges will be upgraded to "elkRouted" by elkLayout
 * after ELK computes their ORTHOGONAL routing with bendpoints.
 */
function addEdge(builder: FlowBuilder, options: EdgeOptions): void {
  builder.edges.push({
    id: options.id,
    source: options.source,
    target: options.target,
    sourceHandle: options.sourceHandle,
    targetHandle: options.targetHandle,
    type: "smoothstep",
    style: STYLES.edge,
    animated: options.animated,
    markerEnd: options.markerEnd
      ? { type: "arrowclosed" as const, color: "#6e7681" }
      : undefined,
  });
}

/**
 * Creates edges for a binding link with direction awareness.
 * - "forward": arrows point from source → binding → target
 * - "reverse": arrows point from target → binding → source
 * - "bidirectional": arrows on both ends
 */
function addDirectionalBindingEdges(
  builder: FlowBuilder,
  bindingNodeId: string,
  sourceId: string,
  targetId: string,
  direction: "forward" | "reverse" | "bidirectional",
): void {
  if (direction === "reverse") {
    // Reverse: target → binding → source
    addEdge(builder, {
      id: `edge-${bindingNodeId}-from`,
      source: targetId,
      target: bindingNodeId,
      sourceHandle: "left-source",
      targetHandle: "right",
      markerEnd: true,
    });
    addEdge(builder, {
      id: `edge-${bindingNodeId}-to`,
      source: bindingNodeId,
      target: sourceId,
      sourceHandle: "left-source",
      targetHandle: "right",
      markerEnd: true,
    });
  } else if (direction === "bidirectional") {
    // Bidirectional: arrows on both directions (no markerEnd, just the connection)
    addEdge(builder, {
      id: `edge-${bindingNodeId}-from`,
      source: sourceId,
      target: bindingNodeId,
      sourceHandle: "right-source",
      targetHandle: "left",
    });
    addEdge(builder, {
      id: `edge-${bindingNodeId}-to`,
      source: bindingNodeId,
      target: targetId,
      sourceHandle: "right-source",
      targetHandle: "left",
    });
  } else {
    // Forward (default): source → binding → target
    addEdge(builder, {
      id: `edge-${bindingNodeId}-from`,
      source: sourceId,
      target: bindingNodeId,
      sourceHandle: "right-source",
      targetHandle: "left",
      markerEnd: true,
    });
    addEdge(builder, {
      id: `edge-${bindingNodeId}-to`,
      source: bindingNodeId,
      target: targetId,
      sourceHandle: "right-source",
      targetHandle: "left",
      markerEnd: true,
    });
  }
}

// =============================================================================
// SUMMARY NODES (Semantic Zoom)
// =============================================================================

/** Prefix for summary node IDs */
const SUMMARY_PREFIX = "summary-";

function buildSummaryNodes(builder: FlowBuilder, data: DiagramData): void {
  // Build a mapping of service -> connected transports for summary edges
  const serviceTransportPairs = new Map<string, Map<string, number>>();

  data.services.forEach((service, serviceIndex) => {
    const suffix = serviceIndex > 0 ? `-${serviceIndex}` : "";
    const serviceGroupId = `${NODE_IDS.SERVICE_GROUP}${suffix}`;
    const sagaConsumerNames = new Set(service.sagas.map((s) => s.consumerName));
    const regularConsumers = service.consumers.filter(
      (c) => !sagaConsumerNames.has(c.name),
    );

    // Collect transport names connected to this service
    const transportRouteCounts = new Map<string, number>();
    [...service.routes.inbound, ...service.routes.outbound].forEach((route) => {
      const tName = route.endpoint.transportName;
      transportRouteCounts.set(tName, (transportRouteCounts.get(tName) ?? 0) + 1);
    });

    serviceTransportPairs.set(serviceGroupId, transportRouteCounts);

    // Create summary service node (hidden initially, shown at low zoom)
    const summaryNodeId = `${SUMMARY_PREFIX}${serviceGroupId}`;
    builder.nodes.push({
      id: summaryNodeId,
      type: "summaryService",
      position: { x: 0, y: 0 }, // Will be repositioned by elkLayout at group centroid
      data: {
        label: service.host.serviceName,
        consumerCount: regularConsumers.length,
        messageCount: service.messageTypes.length,
        sagaCount: service.sagas.length,
        transportNames: [...transportRouteCounts.keys()],
        serviceGroupId,
      } satisfies SummaryServiceNodeData,
      hidden: true, // Hidden by default (shown at zoom < 0.35)
    });
  });

  // Create summary transport nodes
  data.transports.forEach((transport) => {
    const groupId = `transport-${transport.name}`;
    const summaryNodeId = `${SUMMARY_PREFIX}${groupId}`;

    // Count entities by kind
    const entityCounts: Record<string, number> = {};
    transport.topology.entities.forEach((entity) => {
      entityCounts[entity.kind] = (entityCounts[entity.kind] ?? 0) + 1;
    });

    builder.nodes.push({
      id: summaryNodeId,
      type: "summaryTransport",
      position: { x: 0, y: 0 }, // Will be repositioned by elkLayout at group centroid
      data: {
        label: transport.name,
        entityCounts,
        totalEntityCount: transport.topology.entities.length,
        transportGroupId: groupId,
      } satisfies SummaryTransportNodeData,
      hidden: true, // Hidden by default (shown at zoom < 0.35)
    });
  });

  // Create summary edges: one per (service, transport) pair with route count
  data.services.forEach((_, serviceIndex) => {
    const suffix = serviceIndex > 0 ? `-${serviceIndex}` : "";
    const serviceGroupId = `${NODE_IDS.SERVICE_GROUP}${suffix}`;
    const routeCounts = serviceTransportPairs.get(serviceGroupId);
    if (!routeCounts) return;

    routeCounts.forEach((count, transportName) => {
      const serviceNodeId = `${SUMMARY_PREFIX}${serviceGroupId}`;
      const transportNodeId = `${SUMMARY_PREFIX}transport-${transportName}`;

      builder.edges.push({
        id: `${SUMMARY_PREFIX}edge-${serviceGroupId}-${transportName}`,
        source: serviceNodeId,
        target: transportNodeId,
        sourceHandle: "right-source",
        targetHandle: "left",
        type: "smoothstep",
        style: { stroke: "#6e7681", strokeWidth: 2, opacity: 0.8 },
        label: `${count}`,
        labelStyle: {
          fill: "#8b949e",
          fontSize: 11,
          fontWeight: 600,
        },
        labelBgStyle: {
          fill: "#161b22",
          fillOpacity: 0.9,
        },
        labelBgPadding: [6, 3] as [number, number],
        labelBgBorderRadius: 4,
        hidden: true, // Hidden by default (shown at low zoom)
        data: { isSummaryEdge: true, routeCount: count },
      });
    });
  });
}

// =============================================================================
// ADDRESS PARSING (Transport-Agnostic)
// =============================================================================

/**
 * Parses a transport address to create a unique entity ID.
 *
 * Addresses follow the pattern: scheme://host/prefix/name
 * Common prefixes include:
 * - /e/ for exchanges
 * - /q/ for queues
 * - /t/ for topics
 *
 * This function is transport-agnostic - it extracts the prefix and name
 * without making assumptions about what they represent.
 */
export function addressToEntityId(address: string): string | null {
  // Match address patterns: /prefix/name (single-letter prefix)
  const prefixMatch = address.match(/\/([a-z])\/(.+)$/);
  if (prefixMatch) {
    const [, prefix, name] = prefixMatch;
    return `entity-${prefix}-${name}`;
  }

  // Fallback: use the last segment with a generic prefix
  const segments = address.split("/").filter(Boolean);
  if (segments.length > 0) {
    return `entity-x-${segments[segments.length - 1]}`;
  }

  return null;
}

/**
 * Builds a node ID for a topology entity using its kind.
 * Uses the first letter of the kind as prefix to match address parsing.
 */
function buildEntityNodeId(entity: TopologyEntity): string {
  const prefix = entity.kind.charAt(0);
  return `entity-${prefix}-${entity.name}`;
}

// =============================================================================
// UTILITY FUNCTIONS
// =============================================================================

function getShortName(fullName: string): string {
  return fullName.split(".").pop() || fullName;
}

function truncateLabel(label: string, maxLength: number): string {
  if (label.length <= maxLength) return label;
  return `${label.substring(0, maxLength - 3)}...`;
}

function nodeExists(builder: FlowBuilder, nodeId: string): boolean {
  return builder.nodes.some((n) => n.id === nodeId);
}
