import type { Node, Edge } from "@xyflow/react";
import type { MessageTrace, MessageActivity } from "../types/trace";
import type { DiagramData } from "../types/diagram";
import { addressToEntityId } from "./diagramToFlow";

export interface TraceTopologyMapping {
  /** Node IDs directly observed in trace activities */
  observedNodeIds: Set<string>;
  /** Node IDs inferred from transport topology (exchanges, bindings, queues between dispatch and receive) */
  inferredNodeIds: Set<string>;
  /** All node IDs on the trace path (observed + inferred) */
  nodeIds: Set<string>;
  /** Edge IDs on the trace path */
  edgeIds: Set<string>;
  /** Maps activity ID to its corresponding topology node ID */
  activityToNodeId: Map<string, string>;
  /** Maps topology node ID to its activities */
  nodeIdToActivities: Map<string, MessageActivity[]>;
  /** Ordered list of node IDs representing the trace sequence */
  sequenceNodeIds: string[];
  /** Nodes with errors */
  errorNodeIds: Set<string>;
}

/**
 * Maps a MessageTrace's activities to topology node IDs.
 * Returns the set of node IDs and edge IDs on the trace path,
 * including inferred transport-internal steps.
 */
export function mapTraceToTopology(
  trace: MessageTrace,
  data: DiagramData,
  nodes: Node[],
  edges: Edge[],
): TraceTopologyMapping {
  const observedNodeIds = new Set<string>();
  const inferredNodeIds = new Set<string>();
  const edgeIds = new Set<string>();
  const activityToNodeId = new Map<string, string>();
  const nodeIdToActivities = new Map<string, MessageActivity[]>();
  const sequenceNodeIds: string[] = [];
  const errorNodeIds = new Set<string>();

  // Build a message type identity -> node ID lookup
  const msgTypeToNodeId = buildMessageTypeLookup(nodes);

  // Build topology adjacency for transport-internal inference
  const topologyAdj = buildTopologyAdjacency(edges);

  // Sort activities by start time for sequencing
  const sortedActivities = [...trace.activities].sort(
    (a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime(),
  );

  // Map each activity to its topology node
  for (const activity of sortedActivities) {
    const nodeId = resolveActivityNodeId(activity, msgTypeToNodeId, nodes);
    if (!nodeId) continue;

    // Verify node exists in the topology
    if (!nodes.some((n) => n.id === nodeId)) continue;

    activityToNodeId.set(activity.id, nodeId);
    if (!observedNodeIds.has(nodeId)) {
      sequenceNodeIds.push(nodeId);
    }
    observedNodeIds.add(nodeId);

    if (activity.status === "error") {
      errorNodeIds.add(nodeId);
    }

    // Track node -> activities mapping
    const existing = nodeIdToActivities.get(nodeId);
    if (existing) {
      existing.push(activity);
    } else {
      nodeIdToActivities.set(nodeId, [activity]);
    }
  }

  // Infer transport-internal path between dispatch and receive activities
  inferTransportPath(
    trace,
    data,
    activityToNodeId,
    inferredNodeIds,
    edgeIds,
    topologyAdj,
    edges,
  );

  // Find edges connecting trace-path nodes
  const allTraceNodes = new Set([...observedNodeIds, ...inferredNodeIds]);
  for (const edge of edges) {
    if (allTraceNodes.has(edge.source) && allTraceNodes.has(edge.target)) {
      edgeIds.add(edge.id);
    }
  }

  // Find bridge nodes: intermediate nodes (e.g., route nodes) that sit between
  // two trace-path nodes. Include them so the full visual path is connected.
  // These are NOT marked as inferred (no dashed/faded style) - they appear as
  // regular trace-active nodes.
  const bridgeNodeIds = new Set<string>();
  for (const node of nodes) {
    if (allTraceNodes.has(node.id)) continue;

    let hasInboundFromTrace = false;
    let hasOutboundToTrace = false;
    const bridgeEdges: string[] = [];

    for (const edge of edges) {
      if (edge.target === node.id && allTraceNodes.has(edge.source)) {
        hasInboundFromTrace = true;
        bridgeEdges.push(edge.id);
      }
      if (edge.source === node.id && allTraceNodes.has(edge.target)) {
        hasOutboundToTrace = true;
        bridgeEdges.push(edge.id);
      }
    }

    if (hasInboundFromTrace && hasOutboundToTrace) {
      bridgeNodeIds.add(node.id);
      allTraceNodes.add(node.id);
      for (const eid of bridgeEdges) {
        edgeIds.add(eid);
      }
    }
  }

  const nodeIds = new Set([...observedNodeIds, ...inferredNodeIds, ...bridgeNodeIds]);

  return {
    observedNodeIds,
    inferredNodeIds,
    nodeIds,
    edgeIds,
    activityToNodeId,
    nodeIdToActivities,
    sequenceNodeIds,
    errorNodeIds,
  };
}

function resolveActivityNodeId(
  activity: MessageActivity,
  msgTypeToNodeId: Map<string, string>,
  nodes: Node[],
): string | null {
  switch (activity.operation) {
    case "publish":
    case "send":
    case "request":
    case "reply":
    case "subscribe":
      return msgTypeToNodeId.get(activity.messageTypeIdentity) ?? null;
    case "dispatch":
      return `dispatch-${activity.endpointName}`;
    case "receive":
      return `receive-${activity.endpointName}`;
    case "consume": {
      // Search for the consumer or saga node by name.
      // Node IDs contain a service-index suffix (e.g. consumer-1-Foo) so we
      // cannot hard-code the ID - instead match via fullData.
      const consumerNode = nodes.find((n) => {
        const data = n.data as Record<string, unknown>;
        const fullData = data.fullData as Record<string, unknown> | undefined;
        if (!fullData) return false;
        if (data.nodeType === "saga") {
          return fullData.consumerName === activity.consumerName;
        }
        if (data.nodeType === "consumer") {
          return fullData.name === activity.consumerName;
        }
        return false;
      });
      return consumerNode?.id ?? null;
    }
    case "saga-transition":
      return `saga-${activity.sagaName}`;
  }
}

function buildMessageTypeLookup(nodes: Node[]): Map<string, string> {
  const lookup = new Map<string, string>();
  for (const node of nodes) {
    const data = node.data as Record<string, unknown>;
    if (data.nodeType === "message" && data.fullData) {
      const fullData = data.fullData as Record<string, unknown>;
      if (typeof fullData.identity === "string") {
        lookup.set(fullData.identity, node.id);
      }
    }
  }
  return lookup;
}

function buildTopologyAdjacency(
  edges: Edge[],
): Map<string, { nodeId: string; edgeId: string }[]> {
  const adj = new Map<string, { nodeId: string; edgeId: string }[]>();
  for (const edge of edges) {
    const sourceAdj = adj.get(edge.source);
    const entry = { nodeId: edge.target, edgeId: edge.id };
    if (sourceAdj) {
      sourceAdj.push(entry);
    } else {
      adj.set(edge.source, [entry]);
    }
  }
  return adj;
}

/**
 * Infers the transport-internal path between dispatch and receive activities.
 * Uses BFS through the topology graph to find paths from dispatch endpoint
 * destinations (exchanges) to receive endpoint sources (queues).
 */
function inferTransportPath(
  trace: MessageTrace,
  data: DiagramData,
  activityToNodeId: Map<string, string>,
  inferredNodeIds: Set<string>,
  edgeIds: Set<string>,
  topologyAdj: Map<string, { nodeId: string; edgeId: string }[]>,
  edges: Edge[],
): void {
  // Find dispatch and receive activity pairs
  const dispatchActivities = trace.activities.filter(
    (a) => a.operation === "dispatch",
  );
  const receiveActivities = trace.activities.filter(
    (a) => a.operation === "receive",
  );

  for (const dispatch of dispatchActivities) {
    if (dispatch.operation !== "dispatch") continue;

    const dispatchNodeId = activityToNodeId.get(dispatch.id);
    if (!dispatchNodeId) continue;

    // Find the transport entity that this dispatch endpoint connects to
    // by looking up the dispatch endpoint's destination address in the transport data
    const dispatchEndpoint = findDispatchEndpoint(data, dispatch.endpointName);
    if (!dispatchEndpoint) continue;

    const destEntityId = addressToEntityId(dispatchEndpoint.destinationAddress);
    if (!destEntityId) continue;

    // Find the edge from dispatch endpoint to the destination entity
    const dispatchToEntityEdge = edges.find(
      (e) => e.source === dispatchNodeId && e.target === destEntityId,
    );
    if (dispatchToEntityEdge) {
      edgeIds.add(dispatchToEntityEdge.id);
    }

    // For each receive activity with matching message type, find if there's a path through the transport
    for (const receive of receiveActivities) {
      if (receive.operation !== "receive") continue;
      if (receive.messageTypeIdentity !== dispatch.messageTypeIdentity) continue;

      const receiveNodeId = activityToNodeId.get(receive.id);
      if (!receiveNodeId) continue;

      // Find the transport entity that feeds this receive endpoint
      const receiveEndpoint = findReceiveEndpoint(data, receive.endpointName);
      if (!receiveEndpoint) continue;

      const sourceEntityId = addressToEntityId(receiveEndpoint.sourceAddress);
      if (!sourceEntityId) continue;

      // Find edge from source entity to receive endpoint
      const entityToReceiveEdge = edges.find(
        (e) => e.source === sourceEntityId && e.target === receiveNodeId,
      );
      if (entityToReceiveEdge) {
        edgeIds.add(entityToReceiveEdge.id);
      }

      // BFS from destEntityId to sourceEntityId through transport topology
      const path = bfsPath(destEntityId, sourceEntityId, topologyAdj);
      if (path) {
        for (const step of path) {
          inferredNodeIds.add(step.nodeId);
          edgeIds.add(step.edgeId);
        }
        // Also add the start entity
        inferredNodeIds.add(destEntityId);
      }
    }
  }
}

function findDispatchEndpoint(
  data: DiagramData,
  endpointName: string,
): { destinationAddress: string } | null {
  for (const transport of data.transports) {
    for (const ep of transport.dispatchEndpoints) {
      if (ep.name === endpointName) {
        return { destinationAddress: ep.destination.address };
      }
    }
  }
  return null;
}

function findReceiveEndpoint(
  data: DiagramData,
  endpointName: string,
): { sourceAddress: string } | null {
  for (const transport of data.transports) {
    for (const ep of transport.receiveEndpoints) {
      if (ep.name === endpointName) {
        return { sourceAddress: ep.source.address };
      }
    }
  }
  return null;
}

function bfsPath(
  start: string,
  end: string,
  adj: Map<string, { nodeId: string; edgeId: string }[]>,
): { nodeId: string; edgeId: string }[] | null {
  if (start === end) return [];

  const visited = new Set<string>([start]);
  const queue: { nodeId: string; path: { nodeId: string; edgeId: string }[] }[] =
    [];

  const neighbors = adj.get(start);
  if (neighbors) {
    for (const neighbor of neighbors) {
      if (!visited.has(neighbor.nodeId)) {
        visited.add(neighbor.nodeId);
        queue.push({
          nodeId: neighbor.nodeId,
          path: [neighbor],
        });
      }
    }
  }

  while (queue.length > 0) {
    const current = queue.shift()!;

    if (current.nodeId === end) {
      return current.path;
    }

    const currentNeighbors = adj.get(current.nodeId);
    if (currentNeighbors) {
      for (const neighbor of currentNeighbors) {
        if (!visited.has(neighbor.nodeId)) {
          visited.add(neighbor.nodeId);
          queue.push({
            nodeId: neighbor.nodeId,
            path: [...current.path, neighbor],
          });
        }
      }
    }
  }

  return null;
}
