import ELK from "elkjs/lib/elk.bundled.js";
import type { ElkNode, ElkExtendedEdge } from "elkjs";
import type { Node, Edge } from "@xyflow/react";
import type { SagaState } from "../types/diagram";

const elk = new ELK();

const NODE_WIDTH = 180;
const BASE_NODE_HEIGHT = 50;
const RESPONSE_HEIGHT = 16;
const SEND_ACTION_HEIGHT = 14;
const NODE_NODE_SPACING = 60;
const LAYER_SPACING = 120;

function computeNodeHeight(state: SagaState, incomingSendActions: string[]): number {
  let height = BASE_NODE_HEIGHT;
  if (state.response) {
    height += RESPONSE_HEIGHT;
  }
  if (incomingSendActions.length > 0) {
    height += incomingSendActions.length * SEND_ACTION_HEIGHT;
  }
  return height;
}

/**
 * Collect send actions from transitions that target a given state.
 */
function collectIncomingSendActions(
  targetStateName: string,
  states: SagaState[],
): string[] {
  const actions: string[] = [];
  for (const state of states) {
    for (const t of state.transitions) {
      if (t.transitionTo === targetStateName && t.send) {
        for (const s of t.send) {
          actions.push(s.messageType);
        }
      }
    }
  }
  return actions;
}

export interface FocusStateNodeData extends Record<string, unknown> {
  label: string;
  isInitial: boolean;
  isFinal: boolean;
  response?: string;
  sendActions: string[];
}

export interface FocusTransitionEdgeData extends Record<string, unknown> {
  eventType: string;
  transitionKind: "request" | "reply" | "event";
  sendActions: string[];
  sourceStateName: string;
  transitionIndex: number;
}

export async function layoutSagaFocus(
  states: SagaState[],
): Promise<{ nodes: Node[]; edges: Edge[] }> {
  if (states.length === 0) {
    return { nodes: [], edges: [] };
  }

  // Build send actions map per target state
  const sendActionsMap = new Map<string, string[]>();
  for (const state of states) {
    sendActionsMap.set(state.name, collectIncomingSendActions(state.name, states));
  }

  // Build ELK nodes
  const elkNodes: ElkNode[] = states.map((state) => {
    const incomingSends = sendActionsMap.get(state.name) ?? [];
    const height = computeNodeHeight(state, incomingSends);

    const layoutOptions: Record<string, string> = {};
    if (state.isInitial) {
      layoutOptions["elk.layered.layering.layerConstraint"] = "FIRST";
    }
    if (state.isFinal) {
      layoutOptions["elk.layered.layering.layerConstraint"] = "LAST";
    }

    return {
      id: state.name,
      width: NODE_WIDTH,
      height,
      layoutOptions: Object.keys(layoutOptions).length > 0 ? layoutOptions : undefined,
    };
  });

  // Build ELK edges
  const elkEdges: ElkExtendedEdge[] = [];
  for (const state of states) {
    for (let i = 0; i < state.transitions.length; i++) {
      const t = state.transitions[i];
      elkEdges.push({
        id: `${state.name}-${t.transitionTo}-${i}`,
        sources: [state.name],
        targets: [t.transitionTo],
      });
    }
  }

  const graph: ElkNode = {
    id: "saga-focus-root",
    layoutOptions: {
      "elk.algorithm": "layered",
      "elk.direction": "RIGHT",
      "elk.spacing.nodeNode": String(NODE_NODE_SPACING),
      "elk.layered.spacing.nodeNodeBetweenLayers": String(LAYER_SPACING),
      "elk.layered.nodePlacement.strategy": "NETWORK_SIMPLEX",
      "elk.layered.nodePlacement.bk.fixedAlignment": "BALANCED",
      "elk.layered.crossingMinimization.strategy": "LAYER_SWEEP",
    },
    children: elkNodes,
    edges: elkEdges,
  };

  const result = await elk.layout(graph);

  // Convert ELK results to ReactFlow nodes
  const positionMap = new Map<string, { x: number; y: number }>();
  if (result.children) {
    for (const elkNode of result.children) {
      positionMap.set(elkNode.id, { x: elkNode.x ?? 0, y: elkNode.y ?? 0 });
    }
  }

  const nodes: Node[] = states.map((state) => {
    const pos = positionMap.get(state.name) ?? { x: 0, y: 0 };
    const incomingSends = sendActionsMap.get(state.name) ?? [];

    const data: FocusStateNodeData = {
      label: state.name === "__Initial" ? "Initial" : state.name,
      isInitial: state.isInitial,
      isFinal: state.isFinal,
      response: state.response?.eventType,
      sendActions: incomingSends,
    };

    return {
      id: state.name,
      type: "focusState",
      position: pos,
      data,
    };
  });

  const edges: Edge[] = [];
  for (const state of states) {
    for (let i = 0; i < state.transitions.length; i++) {
      const t = state.transitions[i];
      const sendActions = (t.send ?? []).map((s) => s.messageType);

      const data: FocusTransitionEdgeData = {
        eventType: t.eventType,
        transitionKind: t.transitionKind,
        sendActions,
        sourceStateName: state.name,
        transitionIndex: i,
      };

      edges.push({
        id: `${state.name}-${t.transitionTo}-${i}`,
        source: state.name,
        target: t.transitionTo,
        type: "focusTransition",
        data,
      });
    }
  }

  return { nodes, edges };
}
