import { Handle, Position } from '@xyflow/react';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faNetworkWired } from '@fortawesome/free-solid-svg-icons';
import styled from 'styled-components';
import { theme } from '../../styles/theme';

export interface SummaryTransportNodeData {
  label: string;
  /** Entity counts by kind, e.g. { exchange: 4, queue: 8 } */
  entityCounts: Record<string, number>;
  totalEntityCount: number;
  /** The ID of the transport group this summarizes */
  transportGroupId: string;
  [key: string]: unknown;
}

const CardContainer = styled.div`
  display: flex;
  flex-direction: column;
  gap: 8px;
  padding: 18px 24px;
  background: rgba(163, 113, 247, 0.1);
  border: 1px solid ${theme.colors.done.fg};
  border-radius: 10px;
  min-width: 380px;
  max-width: 450px;
  cursor: pointer;
  transition: border-color 0.15s ease, box-shadow 0.15s ease;

  &:hover {
    border-color: ${theme.colors.scale.purple4};
    box-shadow: 0 0 0 1px ${theme.colors.scale.purple4};
  }
`;

const TopRow = styled.div`
  display: flex;
  align-items: center;
  gap: 8px;
`;

const IconWrapper = styled.span`
  font-size: 22px;
  color: ${theme.colors.done.fg};
  width: 26px;
  text-align: center;
  flex-shrink: 0;
`;

const TransportName = styled.span`
  font-weight: 600;
  font-size: 20px;
  color: ${theme.colors.fg.default};
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
`;

const BottomRow = styled.div`
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 15px;
  color: ${theme.colors.fg.muted};
`;

const Stat = styled.span`
  white-space: nowrap;
`;

const Separator = styled.span`
  color: ${theme.colors.border.default};
`;

export function SummaryTransportNode({ data }: { data: SummaryTransportNodeData }) {
  const kindEntries = Object.entries(data.entityCounts);

  // Show kind-level counts if available, otherwise total
  const stats: string[] = kindEntries.length > 0
    ? kindEntries.map(([kind, count]) => `${count} ${kind}s`)
    : [`${data.totalEntityCount} entities`];

  return (
    <CardContainer className="summary-transport-node">
      <Handle type="target" position={Position.Left} id="left" />
      <Handle type="source" position={Position.Left} id="left-source" />
      <Handle type="target" position={Position.Right} id="right" />
      <Handle type="source" position={Position.Right} id="right-source" />

      <TopRow>
        <IconWrapper>
          <FontAwesomeIcon icon={faNetworkWired} />
        </IconWrapper>
        <TransportName title={data.label}>{data.label}</TransportName>
      </TopRow>
      {stats.length > 0 && (
        <BottomRow>
          {stats.map((stat, i) => (
            <span key={i}>
              {i > 0 && <Separator> | </Separator>}
              <Stat>{stat}</Stat>
            </span>
          ))}
        </BottomRow>
      )}
    </CardContainer>
  );
}
