import { useMemo, useState, useCallback, useEffect } from "react";
import styled, { css, keyframes } from "styled-components";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import {
  faChevronUp,
  faChevronDown,
  faPlay,
  faPause,
  faStepForward,
  faStepBackward,
  faExclamationTriangle,
} from "@fortawesome/free-solid-svg-icons";
import { theme } from "../styles/theme";
import type { MessageActivity, MessageTrace } from "../types/trace";

// =============================================================================
// TYPES
// =============================================================================

interface TraceTimelineProps {
  trace: MessageTrace;
  hoveredActivityIds: ReadonlySet<string>;
  onActivityHover: (activity: MessageActivity | null) => void;
  onActivityClick: (activity: MessageActivity) => void;
}

interface TimelineRow {
  activity: MessageActivity;
  depth: number;
  offsetPercent: number;
  widthPercent: number;
}

// =============================================================================
// COLOR SCHEME
// =============================================================================

const OPERATION_COLORS: Record<string, string> = {
  publish: theme.colors.accent.fg,
  send: theme.colors.accent.fg,
  dispatch: theme.colors.accent.fg,
  receive: theme.colors.success.fg,
  consume: "#39d2c0", // teal
  "saga-transition": "#39d2c0",
  reply: theme.colors.done.fg,
  request: theme.colors.accent.fg,
  subscribe: theme.colors.accent.fg,
};

function getOperationColor(operation: string): string {
  return OPERATION_COLORS[operation] ?? theme.colors.fg.muted;
}

function getActivityLabel(activity: MessageActivity): string {
  switch (activity.operation) {
    case "publish":
      return `publish ${activity.messageType}`;
    case "send":
      return `send ${activity.messageType}`;
    case "dispatch":
      return `dispatch ${activity.endpointName}`;
    case "receive":
      return `receive ${activity.endpointName}`;
    case "consume":
      return `consume ${activity.consumerName}`;
    case "saga-transition":
      return `${activity.sagaName}: ${activity.fromState} → ${activity.toState}`;
    case "reply":
      return `reply ${activity.messageType}`;
    case "request":
      return `request ${activity.messageType}`;
    case "subscribe":
      return `subscribe ${activity.messageType}`;
  }
}

// =============================================================================
// COMPONENT
// =============================================================================

const EMPTY_SET = new Set<string>();

export function TraceTimeline({
  trace,
  hoveredActivityIds = EMPTY_SET,
  onActivityHover,
  onActivityClick,
}: TraceTimelineProps) {
  const [collapsed, setCollapsed] = useState(false);
  const [playbackIndex, setPlaybackIndex] = useState<number | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);

  // Build the timeline rows from the trace tree
  const rows = useMemo(() => buildTimelineRows(trace), [trace]);

  // Playback controls
  const sortedActivities = useMemo(
    () =>
      [...trace.activities].sort(
        (a, b) =>
          new Date(a.startTime).getTime() - new Date(b.startTime).getTime(),
      ),
    [trace],
  );

  const handlePlay = useCallback(() => {
    if (isPlaying) {
      setIsPlaying(false);
      return;
    }
    setIsPlaying(true);
    if (playbackIndex === null || playbackIndex >= sortedActivities.length - 1) {
      setPlaybackIndex(0);
      if (sortedActivities[0]) {
        onActivityHover(sortedActivities[0]);
      }
    }
  }, [isPlaying, playbackIndex, sortedActivities, onActivityHover]);

  const handleStepForward = useCallback(() => {
    setPlaybackIndex((prev) => {
      const next = (prev ?? -1) + 1;
      return next < sortedActivities.length ? next : prev;
    });
    setIsPlaying(false);
  }, [sortedActivities.length]);

  const handleStepBackward = useCallback(() => {
    setPlaybackIndex((prev) => {
      const next = (prev ?? 1) - 1;
      return next >= 0 ? next : 0;
    });
    setIsPlaying(false);
  }, []);

  // Auto-advance playback
  useEffect(() => {
    if (!isPlaying || playbackIndex === null) return;

    const timer = setTimeout(() => {
      if (playbackIndex < sortedActivities.length - 1) {
        const nextIdx = playbackIndex + 1;
        setPlaybackIndex(nextIdx);
        onActivityHover(sortedActivities[nextIdx]);
      } else {
        setIsPlaying(false);
      }
    }, 800);

    return () => clearTimeout(timer);
  }, [isPlaying, playbackIndex, sortedActivities, onActivityHover]);

  const totalDurationMs = useMemo(() => {
    if (trace.activities.length === 0) return 0;
    const times = trace.activities.map(
      (a) => new Date(a.startTime).getTime() + a.durationMs,
    );
    const starts = trace.activities.map((a) => new Date(a.startTime).getTime());
    return Math.max(...times) - Math.min(...starts);
  }, [trace]);

  return (
    <PanelContainer $collapsed={collapsed}>
      <PanelHeader onClick={() => setCollapsed(!collapsed)}>
        <HeaderLeft>
          <FontAwesomeIcon
            icon={collapsed ? faChevronUp : faChevronDown}
            size="xs"
          />
          <HeaderTitle>Trace Timeline</HeaderTitle>
          <TraceId>{trace.traceId}</TraceId>
          <ActivityCount>
            {trace.activities.length} activities ·{" "}
            {totalDurationMs.toFixed(0)}ms
          </ActivityCount>
        </HeaderLeft>
        <PlaybackControls onClick={(e) => e.stopPropagation()}>
          {playbackIndex !== null && (
            <PlaybackProgress>
              {playbackIndex + 1}/{sortedActivities.length}
            </PlaybackProgress>
          )}
          <ControlButton onClick={handleStepBackward} title="Step backward" aria-label="Step backward">
            <FontAwesomeIcon icon={faStepBackward} size="xs" />
          </ControlButton>
          <ControlButton onClick={handlePlay} title={isPlaying ? "Pause" : "Play"} aria-label={isPlaying ? "Pause" : "Play"}>
            <FontAwesomeIcon icon={isPlaying ? faPause : faPlay} size="xs" />
          </ControlButton>
          <ControlButton onClick={handleStepForward} title="Step forward" aria-label="Step forward">
            <FontAwesomeIcon icon={faStepForward} size="xs" />
          </ControlButton>
        </PlaybackControls>
      </PanelHeader>

      {!collapsed && (
        <TimelineContent>
          {rows.length === 0 && (
            <EmptyState>No activities recorded for this trace.</EmptyState>
          )}
          {rows.map((row) => (
            <TimelineRowContainer
              key={row.activity.id}
              $depth={row.depth}
              $hovered={hoveredActivityIds.has(row.activity.id)}
              $playing={
                playbackIndex !== null &&
                sortedActivities[playbackIndex]?.id === row.activity.id
              }
              onMouseEnter={() => onActivityHover(row.activity)}
              onMouseLeave={() => onActivityHover(null)}
              onClick={() => onActivityClick(row.activity)}
            >
              <RowLabel $depth={row.depth}>
                {row.activity.status === "error" && (
                  <ErrorIcon>
                    <FontAwesomeIcon icon={faExclamationTriangle} size="xs" />
                  </ErrorIcon>
                )}
                <OperationDot $color={getOperationColor(row.activity.operation)} title={row.activity.operation} />
                <LabelText title={getActivityLabel(row.activity)}>
                  {getActivityLabel(row.activity)}
                </LabelText>
              </RowLabel>
              <BarContainer>
                <Bar
                  $left={row.offsetPercent}
                  $width={Math.max(row.widthPercent, 0.5)}
                  $color={getOperationColor(row.activity.operation)}
                  $error={row.activity.status === "error"}
                />
                {row.activity.durationMs > 0 && (
                  <DurationLabel
                    style={{ left: `${row.offsetPercent + row.widthPercent + 0.5}%` }}
                  >
                    {row.activity.durationMs}ms
                  </DurationLabel>
                )}
              </BarContainer>
            </TimelineRowContainer>
          ))}
        </TimelineContent>
      )}
    </PanelContainer>
  );
}

// =============================================================================
// TIMELINE ROW COMPUTATION
// =============================================================================

function buildTimelineRows(trace: MessageTrace): TimelineRow[] {
  if (trace.activities.length === 0) return [];

  const activities = trace.activities;

  // Find time range
  const startTimes = activities.map((a) => new Date(a.startTime).getTime());
  const endTimes = activities.map(
    (a) => new Date(a.startTime).getTime() + a.durationMs,
  );
  const traceStart = Math.min(...startTimes);
  const traceEnd = Math.max(...endTimes);
  const traceDuration = traceEnd - traceStart || 1;

  // Build parent-child map for depth calculation
  const activityIds = new Set(activities.map((a) => a.id));
  const childrenMap = new Map<string | null, MessageActivity[]>();
  for (const activity of activities) {
    // Treat activities whose parentId is not in the trace as roots
    const parentKey =
      activity.parentId !== null && activityIds.has(activity.parentId)
        ? activity.parentId
        : null;
    const children = childrenMap.get(parentKey);
    if (children) {
      children.push(activity);
    } else {
      childrenMap.set(parentKey, [activity]);
    }
  }

  // DFS to build rows in tree order
  const rows: TimelineRow[] = [];

  function traverse(parentId: string | null, depth: number) {
    const children = [...(childrenMap.get(parentId) ?? [])];
    // Sort children by start time
    children.sort(
      (a, b) =>
        new Date(a.startTime).getTime() - new Date(b.startTime).getTime(),
    );

    for (const activity of children) {
      const actStart = new Date(activity.startTime).getTime();
      const offsetPercent =
        ((actStart - traceStart) / traceDuration) * 100;
      const widthPercent =
        (activity.durationMs / traceDuration) * 100;

      rows.push({
        activity,
        depth,
        offsetPercent,
        widthPercent,
      });

      traverse(activity.id, depth + 1);
    }
  }

  traverse(null, 0);

  return rows;
}

