// =============================================================================
// TYPES
// =============================================================================

export type SidebarTab = "sagas" | "trace" | "search" | "details" | "developer";

export interface LeftSidebarProps {
  sagas: Saga[];
  onSagaClick: (saga: Saga) => void;
  /** Content to render in the Trace tab. When provided, the Trace tab becomes available. */
  traceContent?: ReactNode;
  /** Called when trace focus mode changes (trace tab active + focus toggle on). */
  onTraceFocusChange?: (enabled: boolean) => void;
  /** Search index for the Search tab. When provided with onSearchResultSelect, the Search tab becomes available. */
  searchIndex?: SearchableEntry[];
  /** Called when a search result is selected in the Search tab. */
  onSearchResultSelect?: (nodeId: string) => void;
  /** Selected node to display in the Details tab. When set, the Details tab becomes available. */
  selectedNode?: Node | null;
  /** Called when the user closes the Details tab / deselects the node. */
  onNodeDeselect?: () => void;
  /** Called when the user clicks the Focus button on a saga detail view. */
  onFocusSaga?: (saga: Saga) => void;
  /** Controlled active tab. When provided with onActiveTabChange, the parent owns the tab state. */
  activeTab?: SidebarTab;
  /** Called when the active tab changes. */
  onActiveTabChange?: (tab: SidebarTab) => void;
  /** Controlled collapsed state. When provided with onCollapsedChange, the parent owns the collapsed state. */
  collapsed?: boolean;
  /** Called when the collapsed state changes. */
  onCollapsedChange?: (collapsed: boolean) => void;
  /** Content to render in the Developer tab panel. When provided, the Developer icon appears. */
  developerContent?: ReactNode;
  /**
   * Allowlist of tabs to display. When provided, only these tabs appear
   * regardless of whether their data props are set. When omitted, the
   * automatic detection logic applies (tabs appear when their data is
   * provided).
   */
  visibleTabs?: SidebarTab[];
}

// =============================================================================
// COMPONENT
// =============================================================================

export function LeftSidebar({
  sagas,
  onSagaClick,
  traceContent,
  onTraceFocusChange,
  searchIndex,
  onSearchResultSelect,
  selectedNode,
  onNodeDeselect,
  onFocusSaga,
  activeTab: controlledActiveTab,
  onActiveTabChange,
  collapsed: controlledCollapsed,
  onCollapsedChange,
  developerContent,
  visibleTabs,
}: LeftSidebarProps) {
  // When visibleTabs is provided, use it as an allowlist; otherwise fall
  // back to the automatic "has data" detection.
  const allowSet = visibleTabs ? new Set(visibleTabs) : null;

  const hasSagas = allowSet ? allowSet.has("sagas") : sagas.length > 0;
  const hasTrace = allowSet ? allowSet.has("trace") : !!traceContent;
  const hasSearch = allowSet ? allowSet.has("search") : !!searchIndex && !!onSearchResultSelect;
  const hasDetails = allowSet ? allowSet.has("details") : !!selectedNode;
  const hasDeveloper = allowSet ? allowSet.has("developer") : !!developerContent;

  if (!hasSagas && !hasTrace && !hasSearch && !hasDetails && !hasDeveloper) return null;

  const defaultTab: SidebarTab = hasTrace && !hasSagas ? "trace" : "sagas";

  return (
    <LeftSidebarInner
      sagas={sagas}
      onSagaClick={onSagaClick}
      traceContent={traceContent}
      onTraceFocusChange={onTraceFocusChange}
      searchIndex={searchIndex}
      onSearchResultSelect={onSearchResultSelect}
      selectedNode={selectedNode}
      onNodeDeselect={onNodeDeselect}
      onFocusSaga={onFocusSaga}
      hasSagas={hasSagas}
      hasTrace={hasTrace}
      hasSearch={hasSearch}
      hasDetails={hasDetails}
      hasDeveloper={hasDeveloper}
      defaultTab={defaultTab}
      controlledActiveTab={controlledActiveTab}
      onActiveTabChange={onActiveTabChange}
      controlledCollapsed={controlledCollapsed}
      onCollapsedChange={onCollapsedChange}
      developerContent={developerContent}
    />
  );
}

function LeftSidebarInner({
  sagas,
  onSagaClick,
  traceContent,
  onTraceFocusChange,
  searchIndex,
  onSearchResultSelect,
  selectedNode,
  onNodeDeselect,
  onFocusSaga,
  hasSagas,
  hasTrace,
  hasSearch,
  hasDetails,
  hasDeveloper,
  defaultTab,
  controlledActiveTab,
  onActiveTabChange,
  controlledCollapsed,
  onCollapsedChange,
  developerContent,
}: LeftSidebarProps & {
  hasSagas: boolean;
  hasTrace: boolean;
  hasSearch: boolean;
  hasDetails: boolean;
  hasDeveloper: boolean;
  defaultTab: SidebarTab;
  controlledActiveTab?: SidebarTab;
  onActiveTabChange?: (tab: SidebarTab) => void;
  controlledCollapsed?: boolean;
  onCollapsedChange?: (collapsed: boolean) => void;
}) {
  const [internalTab, setInternalTab] = useState<SidebarTab>(defaultTab);
  const [internalCollapsed, setInternalCollapsed] = useState(true);
  const [traceFocusOn, setTraceFocusOn] = useState(true);

  // Resolve controlled vs uncontrolled
  const activeTab = controlledActiveTab ?? internalTab;
  const collapsed = controlledCollapsed ?? internalCollapsed;

  const setActiveTab = useCallback(
    (tab: SidebarTab) => {
      onActiveTabChange?.(tab);
      if (controlledActiveTab === undefined) setInternalTab(tab);
    },
    [controlledActiveTab, onActiveTabChange],
  );

  const setCollapsed = useCallback(
    (value: boolean) => {
      onCollapsedChange?.(value);
      if (controlledCollapsed === undefined) setInternalCollapsed(value);
    },
    [controlledCollapsed, onCollapsedChange],
  );

  // Notify parent whenever effective trace focus changes
  const notifyFocus = useCallback(
    (tab: SidebarTab, focusOn: boolean) => {
      onTraceFocusChange?.(tab === "trace" && focusOn);
    },
    [onTraceFocusChange],
  );

  const handleIconClick = useCallback((tab: SidebarTab) => {
    if (activeTab === tab && !collapsed) {
      setCollapsed(true);
    } else {
      setActiveTab(tab);
      setCollapsed(false);
    }
    notifyFocus(tab, traceFocusOn);
  }, [activeTab, collapsed, setActiveTab, setCollapsed, notifyFocus, traceFocusOn]);

  const switchTab = useCallback((tab: SidebarTab) => {
    setActiveTab(tab);
    notifyFocus(tab, traceFocusOn);
  }, [setActiveTab, notifyFocus, traceFocusOn]);

  const toggleTraceFocus = () => {
    const next = !traceFocusOn;
    setTraceFocusOn(next);
    notifyFocus(activeTab, next);
  };

  const panelOpen = !collapsed;

  // Fire initial state on mount
  useEffect(() => {
    notifyFocus(defaultTab, true);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    const fallback = () =>
      hasSagas ? "sagas" : hasTrace ? "trace" : hasSearch ? "search" : "sagas";

    if (activeTab === "details" && !hasDetails) {
      switchTab(fallback());
    } else if (activeTab === "trace" && !hasTrace) {
      switchTab(fallback());
    } else if (activeTab === "sagas" && !hasSagas) {
      switchTab(hasTrace ? "trace" : hasSearch ? "search" : "sagas");
    } else if (activeTab === "search" && !hasSearch) {
      switchTab(hasSagas ? "sagas" : hasTrace ? "trace" : "sagas");
    } else if (activeTab === "developer" && !hasDeveloper) {
      switchTab(fallback());
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [hasSagas, hasTrace, hasSearch, hasDetails, hasDeveloper]);

  return (
    <SidebarContainer $panelOpen={panelOpen}>
      <IconRail role="tablist">
        {hasSagas && (
          <RailIconButton
            $active={activeTab === "sagas" && panelOpen}
            onClick={() => handleIconClick("sagas")}
            role="tab"
            aria-selected={activeTab === "sagas" && panelOpen}
            title="Sagas"
            icon={faDiagramProject}
            badge={sagas.length}
          />
        )}
        {hasTrace && (
          <RailIconButton
            $active={activeTab === "trace" && panelOpen}
            onClick={() => handleIconClick("trace")}
            role="tab"
            aria-selected={activeTab === "trace" && panelOpen}
            title="Trace"
            icon={faClock}
          />
        )}
        {hasSearch && (
          <RailIconButton
            $active={activeTab === "search" && panelOpen}
            onClick={() => handleIconClick("search")}
            role="tab"
            aria-selected={activeTab === "search" && panelOpen}
            title="Search"
            icon={faMagnifyingGlass}
          />
        )}
        {hasDetails && (
          <RailIconButton
            $active={activeTab === "details" && panelOpen}
            onClick={() => handleIconClick("details")}
            role="tab"
            aria-selected={activeTab === "details" && panelOpen}
            title="Details"
            icon={faCircleInfo}
          />
        )}
        {hasDeveloper && (
          <BottomSection>
            <RailIconButton
              $active={activeTab === "developer" && panelOpen}
              onClick={() => handleIconClick("developer")}
              role="tab"
              aria-selected={activeTab === "developer" && panelOpen}
              title="Developer"
              icon={faCode}
            />
          </BottomSection>
        )}
      </IconRail>
      {panelOpen && (
        <PanelArea>
          <SidebarContent role="tabpanel">
            {activeTab === "sagas" && hasSagas && (
              <SagaList>
                {sagas.map((saga) => (
                  <SagaItem key={saga.name} onClick={() => onSagaClick(saga)}>
                    <SagaIcon>
                      <FontAwesomeIcon icon={faDiagramProject} />
                    </SagaIcon>
                    <SagaInfo>
                      <SagaName>{saga.name}</SagaName>
                      <SagaMeta>
                        {saga.states.length} states{" · "}
                        {saga.states.reduce(
                          (sum, s) => sum + s.transitions.length,
                          0,
                        )}{" "}
                        transitions
                      </SagaMeta>
                    </SagaInfo>
                    <FocusLabel>Focus &rarr;</FocusLabel>
                  </SagaItem>
                ))}
              </SagaList>
            )}

            {activeTab === "trace" && hasTrace && (
              <>
                <TraceFocusBar>
                  <FocusToggle
                    $active={traceFocusOn}
                    onClick={toggleTraceFocus}
                    title={traceFocusOn ? "Disable trace overlay" : "Enable trace overlay"}
                  >
                    <FontAwesomeIcon icon={faCrosshairs} size="xs" />
                    <span>Focus</span>
                  </FocusToggle>
                </TraceFocusBar>
                <TraceContentWrapper>{traceContent}</TraceContentWrapper>
              </>
            )}

            {activeTab === "search" && hasSearch && (
              <SearchPanel
                searchIndex={searchIndex!}
                onResultSelect={onSearchResultSelect!}
              />
            )}

            {activeTab === "details" && hasDetails && selectedNode && (
              <DetailPanel
                node={selectedNode}
                onClose={onNodeDeselect ?? (() => {})}
                onFocusSaga={onFocusSaga}
                embedded
              />
            )}

            {activeTab === "developer" && hasDeveloper && (
              <DeveloperContentWrapper>{developerContent}</DeveloperContentWrapper>
            )}
          </SidebarContent>
        </PanelArea>
      )}
    </SidebarContainer>
  );
}

// =============================================================================
// ICON BUTTON HELPER
// =============================================================================

function RailIconButton({
  icon,
  badge,
  ...rest
}: React.ButtonHTMLAttributes<HTMLButtonElement> & {
  $active: boolean;
  icon: IconDefinition;
  badge?: number;
}) {
  return (
    <IconButton {...rest}>
      <FontAwesomeIcon icon={icon} />
      {badge != null && badge > 0 && <IconBadge>{badge}</IconBadge>}
    </IconButton>
  );
}

