/**
 * Small component rendered inside <ReactFlow> to pan the viewport
 * when the focused node changes. Must be a child of <ReactFlow>
 * so that useReactFlow() accesses the correct store.
 */
function ViewportPanner({ nodeId }: { nodeId: string | null }) {
  const { getInternalNode, setCenter, getZoom } = useReactFlow();

  useEffect(() => {
    if (!nodeId) return;
    // Small delay so ReactFlow has processed the latest node positions
    const timer = setTimeout(() => {
      const internalNode = getInternalNode(nodeId);
      if (!internalNode) return;
      const pos = internalNode.internals.positionAbsolute;
      const w = internalNode.measured?.width ?? 100;
      const h = internalNode.measured?.height ?? 40;
      const x = pos.x + w / 2;
      const y = pos.y + h / 2;
      const targetZoom = Math.max(getZoom(), 1.5);
      setCenter(x, y, { duration: 400, zoom: targetZoom });
    }, 50);
    return () => clearTimeout(timer);
  }, [nodeId, getInternalNode, setCenter, getZoom]);

  return null;
}

/**
 * Inner component that auto-fits the viewport when the view mode changes.
 * Must be a child of <ReactFlow> to access its context.
 */
function ViewModeSwitcher({ viewMode }: { viewMode: ViewMode }) {
  const { fitView } = useReactFlow();
  const prevMode = useRef(viewMode);

  useEffect(() => {
    if (prevMode.current !== viewMode) {
      prevMode.current = viewMode;
      // Delay so React renders the new visible/hidden nodes before fitting
      setTimeout(() => {
        fitView({ padding: 0.2, duration: 300 });
      }, 50);
    }
  }, [viewMode, fitView]);

  return null;
}

/**
 * Invisible bridge component rendered inside <ReactFlow> that captures
 * the flow API (zoomIn, zoomOut, fitView) and stores it in a ref so
 * components outside the ReactFlow provider can use zoom controls.
 */
function ReactFlowBridge({
  apiRef,
}: {
  apiRef: React.MutableRefObject<Pick<ReactFlowInstance, "zoomIn" | "zoomOut" | "fitView"> | null>;
}) {
  const flow = useReactFlow();

  useEffect(() => {
    apiRef.current = {
      zoomIn: flow.zoomIn,
      zoomOut: flow.zoomOut,
      fitView: flow.fitView,
    };
  }, [flow, apiRef]);

  return null;
}

/**
 * Zoom controls component for the developer pane.
 */
function ZoomControls({
  onZoomIn,
  onZoomOut,
  onFitView,
}: {
  onZoomIn: () => void;
  onZoomOut: () => void;
  onFitView: () => void;
}) {
  return (
    <ZoomControlsWrapper>
      <ZoomControlsLabel>Zoom</ZoomControlsLabel>
      <ZoomControlsRow>
        <ZoomButton onClick={onZoomIn} title="Zoom in">
          <FontAwesomeIcon icon={faMagnifyingGlassPlus} />
        </ZoomButton>
        <ZoomButton onClick={onZoomOut} title="Zoom out">
          <FontAwesomeIcon icon={faMagnifyingGlassMinus} />
        </ZoomButton>
        <ZoomButton onClick={onFitView} title="Fit view">
          <FontAwesomeIcon icon={faExpand} />
        </ZoomButton>
      </ZoomControlsRow>
    </ZoomControlsWrapper>
  );
}

export type EdgeRouting = "smart" | "simple";

interface TopologyFlowProps {
  data: DiagramData;
  trace?: MessageTrace | null;
  /** @deprecated No longer used - trace tab is now part of the LeftSidebar. */
  enableTraceTimeline?: boolean;
  /** Content to render in the left sidebar's Trace tab. When provided, the Trace tab appears. */
  traceContent?: ReactNode;
  activeTraceActivityId?: string;
  /** Focus a specific topology node by ID (takes priority over activeTraceActivityId) */
  focusedTopologyNodeId?: string;
  onTraceActivityClick?: (activity: MessageActivity) => void;
  onTraceActivityHover?: (activity: MessageActivity | null) => void;
  onTraceMappingChange?: (info: {
    traceMapping: import("../utils/traceMapping").TraceTopologyMapping | null;
    nodes: Node[];
    edges: Edge[];
  }) => void;
  traceDisplayMode?: "dim" | "hide";
  /** Edge routing mode: "smart" uses A* pathfinding, "simple" uses default smoothstep */
  edgeRouting?: EdgeRouting;

  // --- View Mode ---

  /** Controlled view mode. 'detail' shows full topology, 'overview' shows summary cards. */
  viewMode?: ViewMode;
  /** Callback when view mode changes. */
  onViewModeChange?: (mode: ViewMode) => void;

  // --- Left Sidebar ---

  /** Controlled active sidebar tab. */
  sidebarTab?: SidebarTab;
  /** Called when the sidebar tab changes. */
  onSidebarTabChange?: (tab: SidebarTab) => void;
  /** Controlled sidebar collapsed state. */
  sidebarCollapsed?: boolean;
  /** Called when the sidebar collapsed state changes. */
  onSidebarCollapsedChange?: (collapsed: boolean) => void;

  // --- Developer Pane ---

  /** Show the developer pane icon in the left sidebar. */
  showDeveloperPane?: boolean;
  /** Custom content to inject into the developer pane (rendered above zoom controls). */
  developerPaneContent?: ReactNode;

  // --- Visibility ---

  /** Completely hide the left sidebar. Default: false */
  hideSidebar?: boolean;
  /** Hide the minimap. Default: false */
  hideMinimap?: boolean;
  /** Hide the controls (zoom +/-, fit, lock). Default: false */
  hideControls?: boolean;

  /**
   * Allowlist of sidebar tabs to show. When provided, only these tabs
   * appear in the sidebar icon rail. Overrides the automatic visibility
   * logic (e.g. hasTrace, hasSagas). The sidebar is still hidden entirely
   * if `hideSidebar` is true.
   *
   * Example: `sidebarTabs={["trace", "details"]}` shows only the Trace
   * and Details tabs.
   */
  sidebarTabs?: SidebarTab[];
}

export function TopologyFlow({
  data,
  trace,
  traceContent,
  activeTraceActivityId,
  focusedTopologyNodeId,
  onTraceActivityHover,
  onTraceMappingChange,
  traceDisplayMode = "dim",
  edgeRouting: _edgeRouting = "smart",
  viewMode: controlledViewMode,
  onViewModeChange,
  sidebarTab,
  onSidebarTabChange,
  sidebarCollapsed,
  onSidebarCollapsedChange,
  showDeveloperPane = false,
  developerPaneContent,
  hideSidebar = false,
  hideMinimap = false,
  hideControls = false,
  sidebarTabs,
}: TopologyFlowProps) {
  const [nodes, setNodes] = useNodesState<Node>([]);
  const [edges, setEdges] = useEdgesState<Edge>([]);

  // Filter out position/select changes so nodes cannot be dragged or selected
  const onNodesChange = useCallback(
    (changes: NodeChange<Node>[]) => {
      const filtered = changes.filter(
        (c) => c.type !== "position" && c.type !== "select",
      );
      if (filtered.length > 0) {
        setNodes((nds) => applyNodeChanges(filtered, nds));
      }
    },
    [setNodes],
  );
  const [selectedNode, setSelectedNode] = useState<Node | null>(null);
  const [hoveredNodeId, setHoveredNodeId] = useState<string | null>(null);
  const [hoveredActivityIds, setHoveredActivityIds] = useState<Set<string>>(new Set());
  const [isLayouting, setIsLayouting] = useState(true);
  const [internalViewMode] = useState<ViewMode>("detail");
  const [focusedSaga, setFocusedSaga] = useState<Saga | null>(null);
  const [traceTabActive, setTraceTabActive] = useState(hideSidebar && !!trace);
  const [searchFocusedNodeId, setSearchFocusedNodeId] = useState<string | null>(null);

  // Internal sidebar state (for uncontrolled mode)
  const [internalSidebarTab, setInternalSidebarTab] = useState<SidebarTab>("sagas");
  const [internalSidebarCollapsed, setInternalSidebarCollapsed] = useState(true);

  // Ref to capture the ReactFlow API for zoom controls outside the provider
  const reactFlowApiRef = useRef<Pick<ReactFlowInstance, "zoomIn" | "zoomOut" | "fitView"> | null>(null);

  // Resolve controlled vs uncontrolled sidebar
  const effectiveSidebarTab = sidebarTab ?? internalSidebarTab;
  const effectiveSidebarCollapsed = sidebarCollapsed ?? internalSidebarCollapsed;

  const handleSidebarTabChange = useCallback(
    (tab: SidebarTab) => {
      onSidebarTabChange?.(tab);
      if (sidebarTab === undefined) setInternalSidebarTab(tab);
    },
    [sidebarTab, onSidebarTabChange],
  );

  const handleSidebarCollapsedChange = useCallback(
    (collapsed: boolean) => {
      onSidebarCollapsedChange?.(collapsed);
      if (sidebarCollapsed === undefined) setInternalSidebarCollapsed(collapsed);
    },
    [sidebarCollapsed, onSidebarCollapsedChange],
  );

  // Resolve controlled vs uncontrolled view mode
  const viewMode = controlledViewMode ?? internalViewMode;

  // Collect all sagas from diagram data
  const allSagas = useMemo(() => {
    const sagas: Saga[] = [];
    for (const service of data.services) {
      for (const saga of service.sagas) {
        sagas.push(saga);
      }
    }
    return sagas;
  }, [data]);

  // Transform and layout
  useEffect(() => {
    async function doLayout() {
      setIsLayouting(true);

      const { nodes: initialNodes, edges: initialEdges } = diagramToFlow(data);

      try {
        const { nodes: layoutedNodes, edges: layoutedEdges } =
          await layoutTopologyWithElk(initialNodes, initialEdges);

        setNodes(layoutedNodes);
        setEdges(layoutedEdges);
      } catch (error) {
        console.error("Layout failed:", error);
        setNodes(initialNodes);
        setEdges(initialEdges);
      }

      setIsLayouting(false);
    }

    doLayout();
  }, [data, setNodes, setEdges]);

  // Map trace to topology when trace is provided
  const traceMapping = useMemo(() => {
    if (!trace || nodes.length === 0) return null;
    return mapTraceToTopology(trace, data, nodes, edges);
  }, [trace, data, nodes, edges]);

  // Notify parent when trace mapping changes
  useEffect(() => {
    onTraceMappingChange?.({ traceMapping, nodes, edges });
  }, [traceMapping, nodes, edges, onTraceMappingChange]);

  // Resolve which topology node is hovered via the trace timeline
  const traceHoveredNodeId = useMemo(() => {
    if (hoveredActivityIds.size === 0 || !traceMapping) return null;
    // Use the first hovered activity to determine the node
    const firstId = hoveredActivityIds.values().next().value;
    return firstId ? (traceMapping.activityToNodeId.get(firstId) ?? null) : null;
  }, [hoveredActivityIds, traceMapping]);

  // The effective highlight target: hover takes priority, then selection
  const effectiveHighlightTarget = hoveredNodeId ?? selectedNode?.id ?? null;

  // Build adjacency list once when edges change - O(E)
  const adjacency = useMemo(() => {
    const adj = new Map<string, { nodeId: string; edgeId: string }[]>();
    for (const edge of edges) {
      let list = adj.get(edge.source);
      if (!list) { list = []; adj.set(edge.source, list); }
      list.push({ nodeId: edge.target, edgeId: edge.id });

      list = adj.get(edge.target);
      if (!list) { list = []; adj.set(edge.target, list); }
      list.push({ nodeId: edge.source, edgeId: edge.id });
    }
    return adj;
  }, [edges]);

  // Compute connected nodes and edges via BFS using adjacency list - O(V+E)
  const { highlightedNodes, highlightedEdges } = useMemo(() => {
    if (!effectiveHighlightTarget) {
      return {
        highlightedNodes: new Set<string>(),
        highlightedEdges: new Set<string>(),
      };
    }

    const connectedNodes = new Set<string>([effectiveHighlightTarget]);
    const connectedEdges = new Set<string>();
    const queue = [effectiveHighlightTarget];

    while (queue.length > 0) {
      const currentId = queue.shift()!;
      const neighbors = adjacency.get(currentId);
      if (!neighbors) continue;

      for (const { nodeId, edgeId } of neighbors) {
        connectedEdges.add(edgeId);
        if (!connectedNodes.has(nodeId)) {
          connectedNodes.add(nodeId);
          queue.push(nodeId);
        }
      }
    }

    return {
      highlightedNodes: connectedNodes,
      highlightedEdges: connectedEdges,
    };
  }, [effectiveHighlightTarget, adjacency]);

  // Build a nodeId -> step number map based on sorted activity indices
  // so badge numbers on nodes match the step list numbering exactly
  const nodeIdToStepNumber = useMemo(() => {
    const map = new Map<string, number>();
    if (!trace || !traceMapping) return map;
    const sorted = [...trace.activities].sort(
      (a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime(),
    );
    sorted.forEach((activity, index) => {
      const nodeId = traceMapping.activityToNodeId.get(activity.id);
      if (nodeId && !map.has(nodeId)) {
        map.set(nodeId, index + 1);
      }
    });
    return map;
  }, [trace, traceMapping]);

  // Resolve focused node: explicit node ID takes priority, then trace, then search
  const focusedNodeId = useMemo(() => {
    if (focusedTopologyNodeId) return focusedTopologyNodeId;
    if (activeTraceActivityId && traceMapping) {
      return traceMapping.activityToNodeId.get(activeTraceActivityId) ?? null;
    }
    if (searchFocusedNodeId) return searchFocusedNodeId;
    return null;
  }, [focusedTopologyNodeId, activeTraceActivityId, traceMapping, searchFocusedNodeId]);

  // Build search index for the search panel
  const searchIndex = useMemo(() => buildSearchIndex(nodes), [nodes]);

  // Apply view-mode visibility and highlighting to nodes
  // Priority: viewMode > trace (only when trace tab active) > hover > default
  const displayNodes = useMemo(() => {
    const hasHighlight = !!effectiveHighlightTarget;
    const hasTrace = !!traceMapping && traceTabActive;
    const activeTraceNodeId = traceHoveredNodeId;
    const isOverview = viewMode === "overview";

    return nodes.map((node) => {
      const isSummary = SUMMARY_NODE_TYPES.has(node.type ?? "");
      const isDetail = DETAIL_NODE_TYPES.has(node.type ?? "");
      const isInteractive = node.type === "compact" || node.type === "route";
      const isSearchHighlighted = searchFocusedNodeId === node.id;

      // Helper to append search-highlight class when needed
      const withSearchHighlight = (cls: string) =>
        isSearchHighlighted ? `${cls} search-highlight`.trim() : cls;

      // View mode visibility: in overview, show summary nodes, hide detail nodes
      // In detail mode, hide summary nodes, show detail nodes
      if (isOverview) {
        if (isDetail) {
          return { ...node, hidden: true };
        }
        if (isSummary) {
          return { ...node, hidden: false };
        }
      } else {
        if (isSummary) {
          return { ...node, hidden: true };
        }
      }

      // For detail mode, apply existing highlighting logic
      if (!hasHighlight && !hasTrace) {
        if (isSearchHighlighted) {
          return { ...node, className: "search-highlight" };
        }
        return node;
      }

      // Trace overlay takes priority over everything
      if (hasTrace) {
        const onTracePath = traceMapping.nodeIds.has(node.id);
        const isInferred = traceMapping.inferredNodeIds.has(node.id);
        const hasError = traceMapping.errorNodeIds.has(node.id);
        const isTraceHovered = activeTraceNodeId === node.id;
        const isFocused = focusedNodeId === node.id;
        const stepNumber = nodeIdToStepNumber.get(node.id);

        if (onTracePath) {
          const classes = ["trace-active"];
          if (isInferred) classes.push("trace-inferred");
          if (hasError) classes.push("trace-error");
          if (isTraceHovered) classes.push("highlighted");
          if (isFocused) classes.push("trace-focused");
          if (isSearchHighlighted) classes.push("search-highlight");
          const updatedData = typeof stepNumber === "number"
            ? { ...node.data, traceSequenceNumber: stepNumber }
            : node.data;
          return { ...node, data: updatedData, className: classes.join(" ") };
        }
        if (traceDisplayMode === "hide" && isInteractive) {
          return { ...node, className: withSearchHighlight("hidden") };
        }
        return { ...node, className: withSearchHighlight(isInteractive ? "dimmed" : "") };
      }

      // Hover highlighting (no trace)
      return {
        ...node,
        className: withSearchHighlight(
          highlightedNodes.has(node.id)
            ? "highlighted"
            : isInteractive
              ? "dimmed"
              : "",
        ),
      };
    });
  }, [nodes, effectiveHighlightTarget, highlightedNodes, traceMapping, traceTabActive, traceHoveredNodeId, traceDisplayMode, focusedNodeId, nodeIdToStepNumber, viewMode, searchFocusedNodeId]);

  // Apply view-mode visibility and highlighting to edges
  const displayEdges = useMemo(() => {
    const hasHighlight = !!effectiveHighlightTarget;
    const hasTrace = !!traceMapping && traceTabActive;
    const isOverview = viewMode === "overview";

    return edges.map((edge) => {
      const isSummaryEdge = !!(edge.data as Record<string, unknown>)?.isSummaryEdge;

      // View mode edge visibility: in overview, show summary edges, hide detail edges
      if (isOverview) {
        if (!isSummaryEdge) {
          return { ...edge, hidden: true };
        }
        return { ...edge, hidden: false };
      } else {
        if (isSummaryEdge) {
          return { ...edge, hidden: true };
        }
      }

      // For detail mode edges, apply existing highlighting
      if (!hasHighlight && !hasTrace) return edge;

      // Trace overlay
      if (hasTrace) {
        const onTracePath = traceMapping.edgeIds.has(edge.id);
        return {
          ...edge,
          animated: onTracePath,
          style: {
            ...edge.style,
            stroke: onTracePath ? theme.colors.accent.fg : "#30363d",
            strokeWidth: onTracePath ? 2 : 1,
            opacity: onTracePath ? 1 : 0.15,
          },
        };
      }

      // Hover highlighting (no trace)
      return {
        ...edge,
        animated: highlightedEdges.has(edge.id),
        style: {
          ...edge.style,
          stroke: highlightedEdges.has(edge.id) ? "#58a6ff" : "#30363d",
          strokeWidth: highlightedEdges.has(edge.id) ? 2 : 1,
          opacity: highlightedEdges.has(edge.id) ? 1 : 0.3,
        },
      };
    });
  }, [edges, effectiveHighlightTarget, highlightedEdges, traceMapping, traceTabActive, viewMode]);

  const onNodeClick = useCallback((_event: React.MouseEvent, node: Node) => {
    // Clicking a summary card switches to detail mode
    if (node.type === "summaryService" || node.type === "summaryTransport") {
      onViewModeChange?.("detail");
      return;
    }
    if (node.type === "compact" || node.type === "route") {
      if (selectedNode?.id === node.id) {
        // Toggle off when clicking the already-selected node
        setSelectedNode(null);
      } else {
        setSelectedNode(node);
        handleSidebarTabChange("details");
        handleSidebarCollapsedChange(false);
      }
    }
  }, [onViewModeChange, selectedNode?.id, handleSidebarTabChange, handleSidebarCollapsedChange]);

  const onNodeDoubleClick = useCallback((_event: React.MouseEvent, node: Node) => {
    const nodeType = typeof node.data.nodeType === "string" ? node.data.nodeType : "";
    if (nodeType === "saga" && node.data.fullData) {
      setFocusedSaga(node.data.fullData as unknown as Saga);
      setSelectedNode(null);
    }
  }, []);

  const hoverTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const onNodeMouseEnter = useCallback(
    (_: React.MouseEvent, node: Node) => {
      if (node.type === "compact" || node.type === "route") {
        if (hoverTimerRef.current) clearTimeout(hoverTimerRef.current);
        hoverTimerRef.current = setTimeout(() => {
          setHoveredNodeId(node.id);
          // When trace is active, highlight all activities for this node
          if (traceMapping) {
            const activities = traceMapping.nodeIdToActivities.get(node.id);
            if (activities && activities.length > 0) {
              setHoveredActivityIds(new Set(activities.map((a) => a.id)));
              onTraceActivityHover?.(activities[0]);
            }
          }
        }, 50);
      }
    },
    [traceMapping, onTraceActivityHover],
  );

  const onNodeMouseLeave = useCallback(() => {
    if (hoverTimerRef.current) clearTimeout(hoverTimerRef.current);
    setHoveredNodeId(null);
    if (traceMapping) {
      setHoveredActivityIds(new Set());
      onTraceActivityHover?.(null);
    }
  }, [traceMapping, onTraceActivityHover]);

  const handleFocusSaga = useCallback((saga: Saga) => {
    setFocusedSaga(saga);
  }, []);

  const handleSearchResultSelect = useCallback(
    (nodeId: string) => {
      setSearchFocusedNodeId(nodeId);
      const node = nodes.find((n) => n.id === nodeId);
      if (node) {
        setSelectedNode(node);
        handleSidebarTabChange("details");
        handleSidebarCollapsedChange(false);
      }
      setTimeout(() => setSearchFocusedNodeId(null), 500);
    },
    [nodes, handleSidebarTabChange, handleSidebarCollapsedChange],
  );

  const onPaneClick = useCallback(() => {
    setSelectedNode(null);
  }, []);

  // Build default trace content when trace is provided but traceContent is not
  const effectiveTraceContent = traceContent ?? (trace ? (
    <TraceTimeline
      trace={trace}
      hoveredActivityIds={hoveredActivityIds}
      onActivityHover={(activity) => {
        if (activity) {
          setHoveredActivityIds(new Set([activity.id]));
          onTraceActivityHover?.(activity);
        } else {
          setHoveredActivityIds(new Set());
          onTraceActivityHover?.(null);
        }
      }}
      onActivityClick={(activity) => {
        if (traceMapping) {
          const nodeId = traceMapping.activityToNodeId.get(activity.id);
          if (nodeId) {
            const node = nodes.find((n) => n.id === nodeId);
            if (node) {
              setSelectedNode(node);
              handleSidebarTabChange("details");
            }
          }
        }
      }}
    />
  ) : undefined);

  // Build combined developer content: user content + zoom controls
  const combinedDeveloperContent = showDeveloperPane ? (
    <>
      {developerPaneContent}
      <ZoomControls
        onZoomIn={() => reactFlowApiRef.current?.zoomIn()}
        onZoomOut={() => reactFlowApiRef.current?.zoomOut()}
        onFitView={() => reactFlowApiRef.current?.fitView({ padding: 0.1, duration: 300 })}
      />
    </>
  ) : undefined;

  if (isLayouting) {
    return (
      <LoadingContainer>
        <LoadingSpinner />
        <span>Loading topology...</span>
      </LoadingContainer>
    );
  }

  return (
    <TopologyContainer>
      <ReactFlow
        nodes={displayNodes}
        edges={displayEdges}
        onNodesChange={onNodesChange}
        onNodeClick={onNodeClick}
        onNodeDoubleClick={onNodeDoubleClick}
        onNodeMouseEnter={onNodeMouseEnter}
        onNodeMouseLeave={onNodeMouseLeave}
        onPaneClick={onPaneClick}
        nodeTypes={nodeTypes}
        edgeTypes={edgeTypes}
        nodesDraggable={false}
        nodesConnectable={false}
        elementsSelectable={false}
        minZoom={0.05}
        fitView
        fitViewOptions={{ padding: 0.1 }}
        defaultEdgeOptions={{
          type: "smoothstep",
          animated: false,
        }}
        proOptions={{ hideAttribution: true }}
      >
        <Background
          variant={BackgroundVariant.Dots}
          gap={20}
          size={1}
          color="#21262d"
        />
        {!hideControls && <Controls />}
        {!hideMinimap && (
          <MiniMap
            nodeColor={(node) => {
              if (node.type === "compact") return theme.colors.accent.fg;
              if (node.type === "route") return theme.colors.done.fg;
              if (node.type === "group") return theme.colors.border.default;
              return "transparent";
            }}
            maskColor="rgba(0, 0, 0, 0.7)"
            pannable
            zoomable
          />
        )}
        <ViewportPanner nodeId={focusedNodeId} />
        <ViewModeSwitcher viewMode={viewMode} />
        {showDeveloperPane && <ReactFlowBridge apiRef={reactFlowApiRef} />}
      </ReactFlow>

      {focusedSaga && (
        <SagaFocusOverlay
          saga={focusedSaga}
          onClose={() => setFocusedSaga(null)}
        />
      )}

      {!hideSidebar && !focusedSaga && (
        <LeftSidebar
          sagas={allSagas}
          onSagaClick={handleFocusSaga}
          traceContent={effectiveTraceContent}
          onTraceFocusChange={setTraceTabActive}
          searchIndex={searchIndex}
          onSearchResultSelect={handleSearchResultSelect}
          selectedNode={selectedNode}
          onNodeDeselect={() => setSelectedNode(null)}
          onFocusSaga={handleFocusSaga}
          activeTab={effectiveSidebarTab}
          onActiveTabChange={handleSidebarTabChange}
          collapsed={effectiveSidebarCollapsed}
          onCollapsedChange={handleSidebarCollapsedChange}
          developerContent={combinedDeveloperContent}
          visibleTabs={sidebarTabs}
        />
      )}
    </TopologyContainer>
  );
}

