import { useState, useEffect, useCallback, useMemo } from "react";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import {
  faArrowLeft,
  faDiagramProject,
  faTimes,
} from "@fortawesome/free-solid-svg-icons";
import styled, { css, keyframes } from "styled-components";
import { theme } from "../styles/theme";
import { SagaStateMachine } from "./SagaStateMachine";
import type { Saga, SagaState, SagaTransition } from "../types/diagram";

interface SagaFocusOverlayProps {
  saga: Saga;
  onClose: () => void;
}

interface DrawerContent {
  type: "state" | "transition";
  stateName?: string;
  state?: SagaState;
  transition?: SagaTransition;
  sourceStateName?: string;
}

export function SagaFocusOverlay({ saga, onClose }: SagaFocusOverlayProps) {
  const [drawer, setDrawer] = useState<DrawerContent | null>(null);

  // Escape key handler: close drawer first, then close overlay
  useEffect(() => {
    function handleKeyDown(e: KeyboardEvent) {
      if (e.key === "Escape") {
        if (drawer) {
          setDrawer(null);
        } else {
          onClose();
        }
      }
    }
    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [drawer, onClose]);

  const handleStateClick = useCallback(
    (stateName: string) => {
      const state = saga.states.find((s) => s.name === stateName);
      if (state) {
        setDrawer({ type: "state", stateName: state.name, state });
      }
    },
    [saga.states],
  );

  const handleTransitionClick = useCallback(
    (sourceName: string, transitionIndex: number) => {
      const sourceState = saga.states.find((s) => s.name === sourceName);
      if (sourceState && sourceState.transitions[transitionIndex]) {
        setDrawer({
          type: "transition",
          transition: sourceState.transitions[transitionIndex],
          sourceStateName: sourceName,
        });
      }
    },
    [saga.states],
  );

  // Stats for status bar
  const stats = useMemo(() => {
    let totalTransitions = 0;
    const kindCounts: Record<string, number> = {};
    for (const state of saga.states) {
      for (const t of state.transitions) {
        totalTransitions++;
        kindCounts[t.transitionKind] = (kindCounts[t.transitionKind] ?? 0) + 1;
      }
    }
    return { stateCount: saga.states.length, totalTransitions, kindCounts };
  }, [saga.states]);

  return (
    <Overlay>
      <HeaderBar>
        <BackButton onClick={onClose}>
          <FontAwesomeIcon icon={faArrowLeft} />
          <span>Back to Topology</span>
        </BackButton>
        <HeaderTitle>
          <FontAwesomeIcon icon={faDiagramProject} />
          <span>{saga.name}</span>
        </HeaderTitle>
        <HeaderSpacer />
      </HeaderBar>

      <CanvasArea>
        <SagaStateMachine
          states={saga.states}
          mode="focus"
          onStateClick={handleStateClick}
          onTransitionClick={handleTransitionClick}
        />
      </CanvasArea>

      <StatusBar>
        <StatusItem>{stats.stateCount} states</StatusItem>
        <StatusDivider />
        <StatusItem>{stats.totalTransitions} transitions</StatusItem>
        {Object.entries(stats.kindCounts).map(([kind, count]) => (
          <span key={kind}>
            <StatusDivider />
            <StatusKind $kind={kind}>
              {count} {kind}
            </StatusKind>
          </span>
        ))}
      </StatusBar>

      {drawer && (
        <SideDrawer $open>
          <DrawerHeader>
            <DrawerTitle>
              {drawer.type === "state" ? "State Details" : "Transition Details"}
            </DrawerTitle>
            <DrawerClose onClick={() => setDrawer(null)}>
              <FontAwesomeIcon icon={faTimes} />
            </DrawerClose>
          </DrawerHeader>
          <DrawerBody>
            {drawer.type === "state" && drawer.state && (
              <StateDetails state={drawer.state} allStates={saga.states} />
            )}
            {drawer.type === "transition" && drawer.transition && (
              <TransitionDetails
                transition={drawer.transition}
                sourceStateName={drawer.sourceStateName ?? ""}
              />
            )}
          </DrawerBody>
        </SideDrawer>
      )}
    </Overlay>
  );
}

function StateDetails({ state, allStates }: { state: SagaState; allStates: SagaState[] }) {
  // Collect incoming transitions
  const incoming: Array<{ from: string; transition: SagaTransition }> = [];
  for (const s of allStates) {
    for (const t of s.transitions) {
      if (t.transitionTo === state.name) {
        incoming.push({ from: s.name, transition: t });
      }
    }
  }

  return (
    <>
      <DetailSection>
        <DetailLabel>Name</DetailLabel>
        <DetailValue>{state.name}</DetailValue>
      </DetailSection>
      <DetailSection>
        <DetailLabel>Type</DetailLabel>
        <DetailValue>
          {state.isInitial && <DetailBadge $color="blue">Initial</DetailBadge>}
          {state.isFinal && <DetailBadge $color="green">Final</DetailBadge>}
          {!state.isInitial && !state.isFinal && <span>Intermediate</span>}
        </DetailValue>
      </DetailSection>
      {state.response && (
        <DetailSection>
          <DetailLabel>Response</DetailLabel>
          <DetailMono>{state.response.eventType}</DetailMono>
        </DetailSection>
      )}
      {state.transitions.length > 0 && (
        <DetailSection>
          <DetailLabel>Outgoing Transitions ({state.transitions.length})</DetailLabel>
          {state.transitions.map((t, i) => (
            <TransitionCard key={i}>
              <TransitionEvent>{t.eventType}</TransitionEvent>
              <TransitionMeta>
                <DetailBadge $color={kindColor(t.transitionKind)}>
                  {t.transitionKind}
                </DetailBadge>
                <span>&rarr; {t.transitionTo}</span>
              </TransitionMeta>
              {t.send && t.send.length > 0 && (
                <SendList>
                  {t.send.map((s, j) => (
                    <SendItem key={j}>&uarr; {s.messageType}</SendItem>
                  ))}
                </SendList>
              )}
            </TransitionCard>
          ))}
        </DetailSection>
      )}
      {incoming.length > 0 && (
        <DetailSection>
          <DetailLabel>Incoming Transitions ({incoming.length})</DetailLabel>
          {incoming.map((item, i) => (
            <TransitionCard key={i}>
              <TransitionEvent>{item.transition.eventType}</TransitionEvent>
              <TransitionMeta>
                <DetailBadge $color={kindColor(item.transition.transitionKind)}>
                  {item.transition.transitionKind}
                </DetailBadge>
                <span>&larr; {item.from}</span>
              </TransitionMeta>
            </TransitionCard>
          ))}
        </DetailSection>
      )}
    </>
  );
}

function TransitionDetails({
  transition,
  sourceStateName,
}: {
  transition: SagaTransition;
  sourceStateName: string;
}) {
  return (
    <>
      <DetailSection>
        <DetailLabel>Event Type</DetailLabel>
        <DetailMono>{transition.eventType}</DetailMono>
      </DetailSection>
      {transition.eventTypeFullName !== transition.eventType && (
        <DetailSection>
          <DetailLabel>Full Name</DetailLabel>
          <DetailMono $small>{transition.eventTypeFullName}</DetailMono>
        </DetailSection>
      )}
      <DetailSection>
        <DetailLabel>Kind</DetailLabel>
        <DetailBadge $color={kindColor(transition.transitionKind)}>
          {transition.transitionKind}
        </DetailBadge>
      </DetailSection>
      <DetailSection>
        <DetailLabel>From</DetailLabel>
        <DetailValue>{sourceStateName}</DetailValue>
      </DetailSection>
      <DetailSection>
        <DetailLabel>To</DetailLabel>
        <DetailValue>{transition.transitionTo}</DetailValue>
      </DetailSection>
      {transition.send && transition.send.length > 0 && (
        <DetailSection>
          <DetailLabel>Send Actions ({transition.send.length})</DetailLabel>
          {transition.send.map((s, i) => (
            <SendCard key={i}>
              <DetailMono>{s.messageType}</DetailMono>
              {s.messageTypeFullName !== s.messageType && (
                <DetailMono $small>{s.messageTypeFullName}</DetailMono>
              )}
            </SendCard>
          ))}
        </DetailSection>
      )}
    </>
  );
}

function kindColor(kind: string): string {
  switch (kind) {
    case "request":
      return "blue";
    case "reply":
      return "green";
    case "event":
      return "orange";
    default:
      return "blue";
  }
}

