import { Handle, Position } from '@xyflow/react';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faServer } from '@fortawesome/free-solid-svg-icons';
import styled from 'styled-components';
import { theme } from '../../styles/theme';

export interface SummaryServiceNodeData {
  label: string;
  consumerCount: number;
  messageCount: number;
  sagaCount: number;
  transportNames: string[];
  /** The ID of the service group this summarizes */
  serviceGroupId: string;
  [key: string]: unknown;
}

const CardContainer = styled.div`
  display: flex;
  flex-direction: column;
  gap: 8px;
  padding: 18px 24px;
  background: ${theme.colors.canvas.subtle};
  border: 1px solid ${theme.colors.border.default};
  border-radius: 10px;
  min-width: 450px;
  max-width: 520px;
  cursor: pointer;
  transition: border-color 0.15s ease, box-shadow 0.15s ease;

  &:hover {
    border-color: ${theme.colors.accent.fg};
    box-shadow: 0 0 0 1px ${theme.colors.accent.fg};
  }
`;

const TopRow = styled.div`
  display: flex;
  align-items: center;
  gap: 8px;
`;

const IconWrapper = styled.span`
  font-size: 22px;
  color: ${theme.colors.fg.muted};
  width: 26px;
  text-align: center;
  flex-shrink: 0;
`;

const ServiceName = styled.span`
  font-weight: 600;
  font-size: 20px;
  color: ${theme.colors.fg.default};
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
`;

const BottomRow = styled.div`
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 15px;
  color: ${theme.colors.fg.muted};
`;

const Stat = styled.span`
  white-space: nowrap;
`;

const Separator = styled.span`
  color: ${theme.colors.border.default};
`;

export function SummaryServiceNode({ data }: { data: SummaryServiceNodeData }) {
  const stats: string[] = [];
  if (data.consumerCount > 0) stats.push(`${data.consumerCount} consumers`);
  if (data.messageCount > 0) stats.push(`${data.messageCount} messages`);
  if (data.sagaCount > 0) stats.push(`${data.sagaCount} sagas`);
  if (data.transportNames.length > 0) stats.push(data.transportNames.join(', '));

  return (
    <CardContainer className="summary-service-node">
      <Handle type="target" position={Position.Left} id="left" />
      <Handle type="source" position={Position.Left} id="left-source" />
      <Handle type="target" position={Position.Right} id="right" />
      <Handle type="source" position={Position.Right} id="right-source" />

      <TopRow>
        <IconWrapper>
          <FontAwesomeIcon icon={faServer} />
        </IconWrapper>
        <ServiceName title={data.label}>{data.label}</ServiceName>
      </TopRow>
      {stats.length > 0 && (
        <BottomRow>
          {stats.map((stat, i) => (
            <span key={i}>
              {i > 0 && <Separator> | </Separator>}
              <Stat>{stat}</Stat>
            </span>
          ))}
        </BottomRow>
      )}
    </CardContainer>
  );
}
