import ELK from "elkjs/lib/elk.bundled.js";
import type { ElkNode, ElkExtendedEdge } from "elkjs";
import type { Node, Edge } from "@xyflow/react";
import { generateSmoothStepPath, type Point } from "./pathfinding";

const elk = new ELK();

// Layout constants
const NODE_WIDTH = 180;
const NODE_HEIGHT = 40;
const ROUTE_WIDTH = 70;
const ROUTE_HEIGHT = 30;
const BINDING_WIDTH = 50;
const BINDING_HEIGHT = 26;
const GROUP_PADDING = 20;
const TITLE_HEIGHT = 35;
const SUBGROUP_GAP = 15;
const NODE_SPACING_Y = 12;
const COLUMN_SPACING = 50;
const GROUP_GAP = 40;

// =============================================================================
// MAIN ENTRY POINT
// =============================================================================

function createEdgeIndex(edges: Edge[]) {
  const index = new Map<string, Set<string>>();

  function add(source: string, target: string) {
    const positions = index.get(source);
    if (positions) {
      positions.add(target);
    } else {
      index.set(source, new Set([target]));
    }
  }

  for (const edge of edges) {
    add(edge.source, edge.target);
    add(edge.target, edge.source);
  }

  return {
    get: (source: string) => index.get(source),
  };
}

type EdgeIndex = ReturnType<typeof createEdgeIndex>;

export async function layoutTopologyWithElk(
  nodes: Node[],
  edges: Edge[],
): Promise<{ nodes: Node[]; edges: Edge[] }> {
  const updatedNodes = [...nodes];
  const updatedEdges = [...edges];

  const edgeIndex = createEdgeIndex(edges);

  // Find all service groups and their subflows
  const serviceGroups = updatedNodes.filter(
    (n) => n.type === "group" && n.id.startsWith("service-group"),
  );

  // Layout each service's inbound and outbound subflows
  for (const serviceGroup of serviceGroups) {
    const suffix = serviceGroup.id.replace("service-group", "");
    const inboundId = `inbound-subflow${suffix}`;
    const outboundId = `outbound-subflow${suffix}`;

    layoutByColumns(updatedNodes, edgeIndex, inboundId);
    layoutByColumns(updatedNodes, edgeIndex, outboundId);

    resizeGroup(updatedNodes, inboundId);
    resizeGroup(updatedNodes, outboundId);
  }

  // Transport groups: use ELK for automatic layering (variable depth)
  // Also extracts ELK edge routing data (ORTHOGONAL bendpoints)
  const transportGroups = updatedNodes.filter(
    (n) => n.type === "group" && n.id.startsWith("transport-"),
  );
  for (const group of transportGroups) {
    await layoutTransportWithElk(updatedNodes, updatedEdges, group.id);
    resizeGroup(updatedNodes, group.id);
  }

  // Position all groups
  positionGroups(updatedNodes, serviceGroups, transportGroups);

  // Convert ELK-local edge bendpoints to absolute coordinates
  applyAbsoluteEdgePaths(updatedNodes, updatedEdges);

  // Position summary nodes at the centroid of their respective groups
  positionSummaryNodes(updatedNodes);

  return { nodes: updatedNodes, edges: updatedEdges };
}

// =============================================================================
// SIMPLE COLUMN LAYOUT (for service subflows with fixed 3-column structure)
// =============================================================================

function layoutByColumns(
  nodes: Node[],
  edgeIndex: EdgeIndex,
  groupId: string,
): void {
  const children = nodes.filter(
    (n) =>
      n.parentId === groupId && (n.type === "compact" || n.type === "route"),
  );
  if (children.length === 0) return;

  // Separate into columns by elkLayer
  const left: Node[] = [];
  const middle: Node[] = [];
  const right: Node[] = [];

  for (const node of children) {
    const layer = (node.data as { elkLayer?: string })?.elkLayer;
    if (layer === "FIRST") left.push(node);
    else if (layer === "LAST") right.push(node);
    else middle.push(node);
  }

  // Calculate X positions for each column
  const col1X = GROUP_PADDING;
  const col2X = left.length > 0 ? col1X + NODE_WIDTH + COLUMN_SPACING : col1X;
  const col3X =
    middle.length > 0 ? col2X + ROUTE_WIDTH + COLUMN_SPACING : col2X;

  // Position each column
  let positionedNodes = positionColumnNodes(nodes, right, col3X);
  positionedNodes = positionColumnNodesRanked(
    nodes,
    middle,
    col2X,
    positionedNodes,
    edgeIndex,
  );
  positionColumnNodesRanked(nodes, left, col1X, positionedNodes, edgeIndex);
}

function positionColumnNodes(
  allNodes: Node[],
  columnNodes: Node[],
  x: number,
): Node[] {
  const nodes = [];
  let y = GROUP_PADDING + TITLE_HEIGHT;
  for (const node of columnNodes) {
    const idx = allNodes.findIndex((n) => n.id === node.id);
    if (idx !== -1) {
      allNodes[idx] = { ...allNodes[idx], position: { x, y } };
      y += getNodeHeight(node) + NODE_SPACING_Y;
      nodes.push(node);
    }
  }

  return nodes;
}

function positionColumnNodesRanked(
  allNodes: Node[],
  columnNodes: Node[],
  x: number,
  previousColumn: Node[],
  edgeIndex: EdgeIndex,
): Node[] {
  const positioned: Node[] = [];

  // Sort nodes by the index of their connected node in the previous column
  // so they appear in the same vertical order as their neighbours
  columnNodes = columnNodes.sort((a, b) => {
    const aLinks = edgeIndex.get(a.id);
    const bLinks = edgeIndex.get(b.id);

    const aIndex =
      aLinks !== undefined
        ? previousColumn.findIndex((x) => aLinks.has(x.id))
        : -1;

    const bIndex =
      bLinks !== undefined
        ? previousColumn.findIndex((x) => bLinks.has(x.id))
        : -1;

    if (aIndex === bIndex) {
      return 0;
    }
    if (aIndex < 0) {
      return 1;
    }
    if (bIndex < 0) {
      return -1;
    }
    if (aIndex < bIndex) {
      return -1;
    }
    return 1;
  });

  // Build a lookup: previous-column node id → its positioned Y and height
  const prevPositions = new Map<string, { y: number; h: number }>();
  for (const prev of previousColumn) {
    const prevInAll = allNodes.find((n) => n.id === prev.id);
    if (prevInAll) {
      prevPositions.set(prev.id, {
        y: prevInAll.position.y,
        h: getNodeHeight(prev),
      });
    }
  }

  // Position each node, trying to align its vertical centre with its
  // connected previous-column node. A running minY prevents overlap.
  let minY = GROUP_PADDING + TITLE_HEIGHT;

  for (const node of columnNodes) {
    const nodeH = getNodeHeight(node);
    const links = edgeIndex.get(node.id);

    // Find the connected node in the previous column to get its Y
    let targetY = minY;
    if (links) {
      for (const prev of previousColumn) {
        if (links.has(prev.id)) {
          const prevPos = prevPositions.get(prev.id);
          if (prevPos) {
            // Centre-align this node with the connected previous-column node
            targetY = prevPos.y + prevPos.h / 2 - nodeH / 2;
          }
          break;
        }
      }
    }

    // Ensure no overlap with the previous node in this column
    const y = Math.max(targetY, minY);

    const idx = allNodes.findIndex((n) => n.id === node.id);
    if (idx !== -1) {
      allNodes[idx] = { ...allNodes[idx], position: { x, y } };
    }

    minY = y + nodeH + NODE_SPACING_Y;
    positioned.push(node);
  }

  return positioned;
}

// =============================================================================
// ELK LAYOUT FOR TRANSPORT (handles entities and bindings)
// =============================================================================

async function layoutTransportWithElk(
  nodes: Node[],
  edges: Edge[],
  groupId: string,
): Promise<void> {
  // Get all children (both compact entities and route/binding nodes)
  const children = nodes.filter(
    (n) =>
      n.parentId === groupId && (n.type === "compact" || n.type === "route"),
  );
  if (children.length === 0) return;

  // Get edges where both endpoints are in this group
  const childIds = new Set(children.map((n) => n.id));
  const internalEdges = edges.filter(
    (e) => childIds.has(e.source) && childIds.has(e.target),
  );

  // Build ELK nodes
  const elkNodes: ElkNode[] = children.map((node) => {
    const layer = (node.data as { elkLayer?: string })?.elkLayer;
    const nodeType = (node.data as { nodeType?: string })?.nodeType;

    let width = NODE_WIDTH;
    let height = NODE_HEIGHT;
    if (node.type === "route" || nodeType === "binding") {
      width = BINDING_WIDTH;
      height = BINDING_HEIGHT;
    }

    return {
      id: node.id,
      width,
      height,
      layoutOptions: layer
        ? { "elk.layered.layering.layerConstraint": layer }
        : undefined,
    };
  });

  const elkEdges: ElkExtendedEdge[] = internalEdges.map((edge) => ({
    id: edge.id,
    sources: [edge.source],
    targets: [edge.target],
  }));

  const graph: ElkNode = {
    id: groupId,
    layoutOptions: {
      "elk.algorithm": "layered",
      "elk.direction": "RIGHT",
      "elk.spacing.nodeNode": "35",
      "elk.layered.spacing.nodeNodeBetweenLayers": "80",
      "elk.layered.spacing.edgeNodeBetweenLayers": "35",
      "elk.layered.spacing.edgeEdgeBetweenLayers": "20",
      "elk.layered.nodePlacement.strategy": "NETWORK_SIMPLEX",
      "elk.layered.nodePlacement.bk.fixedAlignment": "BALANCED",
      "elk.layered.crossingMinimization.strategy": "LAYER_SWEEP",
      "elk.layered.considerModelOrder.strategy": "NODES_AND_EDGES",
      "elk.edgeRouting": "ORTHOGONAL",
    },
    children: elkNodes,
    edges: elkEdges,
  };

  try {
    const result = await elk.layout(graph);
    if (!result.children) return;

    // Apply ELK positions
    const positionedNodes = new Map<string, { x: number; y: number; h: number }>();
    for (const elkNode of result.children) {
      const x = (elkNode.x ?? 0) + GROUP_PADDING;
      const y = (elkNode.y ?? 0) + GROUP_PADDING + TITLE_HEIGHT;
      positionedNodes.set(elkNode.id, { x, y, h: elkNode.height ?? NODE_HEIGHT });

      const idx = nodes.findIndex((n) => n.id === elkNode.id);
      if (idx !== -1) {
        nodes[idx] = { ...nodes[idx], position: { x, y } };
      }
    }

    // Extract ELK edge routing sections (ORTHOGONAL bendpoints)
    // Store group-local points on edges; they'll be converted to absolute coords
    // after positionGroups runs.
    if (result.edges) {
      for (const elkEdge of result.edges) {
        if (!elkEdge.sections || elkEdge.sections.length === 0) continue;
        const section = elkEdge.sections[0];

        // Collect all points: start → bendpoints → end (group-local coords)
        const localPoints: Point[] = [];
        localPoints.push({
          x: section.startPoint.x + GROUP_PADDING,
          y: section.startPoint.y + GROUP_PADDING + TITLE_HEIGHT,
        });
        if (section.bendPoints) {
          for (const bp of section.bendPoints) {
            localPoints.push({
              x: bp.x + GROUP_PADDING,
              y: bp.y + GROUP_PADDING + TITLE_HEIGHT,
            });
          }
        }
        localPoints.push({
          x: section.endPoint.x + GROUP_PADDING,
          y: section.endPoint.y + GROUP_PADDING + TITLE_HEIGHT,
        });

        // Store on the edge for later absolute conversion
        const edgeIdx = edges.findIndex((e) => e.id === elkEdge.id);
        if (edgeIdx !== -1) {
          edges[edgeIdx] = {
            ...edges[edgeIdx],
            type: "elkRouted",
            data: {
              ...edges[edgeIdx].data,
              _elkLocalPoints: localPoints,
              _elkGroupId: groupId,
            },
          };
        }
      }
    }

    // Fix isolated LAST nodes: ELK places disconnected nodes at x=0,
    // but they should align with connected LAST nodes
    fixIsolatedLastNodes(nodes, children, internalEdges, positionedNodes);
  } catch (error) {
    console.error(`ELK layout failed for ${groupId}:`, error);
    fallbackGridLayout(nodes, children, groupId);
  }
}

/**
 * ELK doesn't respect layer constraints for nodes without edges.
 * This fixes isolated LAST nodes by moving them to the same X as connected LAST nodes.
 */
function fixIsolatedLastNodes(
  nodes: Node[],
  children: Node[],
  edges: Edge[],
  positionedNodes: Map<string, { x: number; y: number; h: number }>,
): void {
  // Find nodes with edges
  const nodesWithEdges = new Set<string>();
  for (const edge of edges) {
    nodesWithEdges.add(edge.source);
    nodesWithEdges.add(edge.target);
  }

  // Find the X position and max Y of connected LAST nodes
  let lastLayerX: number | null = null;
  let lastLayerMaxY = GROUP_PADDING + TITLE_HEIGHT;

  for (const child of children) {
    const layer = (child.data as { elkLayer?: string })?.elkLayer;
    if (layer === "LAST" && nodesWithEdges.has(child.id)) {
      const pos = positionedNodes.get(child.id);
      if (pos) {
        lastLayerX = pos.x;
        lastLayerMaxY = Math.max(lastLayerMaxY, pos.y + pos.h + NODE_SPACING_Y);
      }
    }
  }

  // Reposition isolated LAST nodes
  if (lastLayerX === null) return; // No connected LAST nodes to align with

  for (const child of children) {
    const layer = (child.data as { elkLayer?: string })?.elkLayer;
    if (layer === "LAST" && !nodesWithEdges.has(child.id)) {
      const idx = nodes.findIndex((n) => n.id === child.id);
      if (idx !== -1) {
        nodes[idx] = { ...nodes[idx], position: { x: lastLayerX, y: lastLayerMaxY } };
        lastLayerMaxY += getNodeHeight(child) + NODE_SPACING_Y;
      }
    }
  }
}

function fallbackGridLayout(
  allNodes: Node[],
  children: Node[],
  _groupId: string,
): void {
  const cols = Math.ceil(Math.sqrt(children.length));
  children.forEach((child, i) => {
    const col = i % cols;
    const row = Math.floor(i / cols);
    const idx = allNodes.findIndex((n) => n.id === child.id);
    if (idx !== -1) {
      allNodes[idx] = {
        ...allNodes[idx],
        position: {
          x: GROUP_PADDING + col * (NODE_WIDTH + 40),
          y: GROUP_PADDING + TITLE_HEIGHT + row * (NODE_HEIGHT + 30),
        },
      };
    }
  });
}

// =============================================================================
// HELPER: Get node dimensions
// =============================================================================

function getNodeWidth(node: Node): number {
  const nodeType = (node.data as { nodeType?: string })?.nodeType;
  if (node.type === "route") {
    return nodeType === "binding" ? BINDING_WIDTH : ROUTE_WIDTH;
  }
  return NODE_WIDTH;
}

function getNodeHeight(node: Node): number {
  const nodeType = (node.data as { nodeType?: string })?.nodeType;
  if (node.type === "route") {
    return nodeType === "binding" ? BINDING_HEIGHT : ROUTE_HEIGHT;
  }
  return NODE_HEIGHT;
}

// =============================================================================
// RESIZE GROUP TO FIT CHILDREN
// =============================================================================

function resizeGroup(nodes: Node[], groupId: string): void {
  const children = nodes.filter(
    (n) =>
      n.parentId === groupId && (n.type === "compact" || n.type === "route"),
  );

  let width: number;
  let height: number;

  if (children.length === 0) {
    // Empty group: use a reasonable minimum that fits the title label
    width = NODE_WIDTH + GROUP_PADDING * 2;
    height = TITLE_HEIGHT + GROUP_PADDING * 2;
  } else {
    let maxX = 0;
    let maxY = 0;
    for (const child of children) {
      const w = getNodeWidth(child);
      const h = getNodeHeight(child);
      maxX = Math.max(maxX, child.position.x + w);
      maxY = Math.max(maxY, child.position.y + h);
    }

    width = maxX + GROUP_PADDING;
    height = maxY + GROUP_PADDING;
  }

  const groupIdx = nodes.findIndex((n) => n.id === groupId);
  if (groupIdx !== -1) {
    nodes[groupIdx] = {
      ...nodes[groupIdx],
      style: { ...nodes[groupIdx].style, width, height },
    };
  }

  // Center title on top border (positioned at center, CSS handles offset)
  const titleIdx = nodes.findIndex((n) => n.id === `${groupId}-title`);
  if (titleIdx !== -1) {
    nodes[titleIdx] = {
      ...nodes[titleIdx],
      position: { x: width / 2, y: 0 },
    };
  }
}

// =============================================================================
// POSITION ALL SERVICE AND TRANSPORT GROUPS
// =============================================================================

function positionGroups(
  nodes: Node[],
  serviceGroups: Node[],
  transportGroups: Node[],
): void {
  // Sort service groups by ID to maintain consistent ordering
  const sortedServices = [...serviceGroups].sort((a, b) =>
    a.id.localeCompare(b.id),
  );

  // Size and position each service group
  const serviceSizes: { w: number; h: number }[] = [];

  for (const serviceGroup of sortedServices) {
    const suffix = serviceGroup.id.replace("service-group", "");
    const inboundId = `inbound-subflow${suffix}`;
    const outboundId = `outbound-subflow${suffix}`;

    const inbound = nodes.find((n) => n.id === inboundId);
    const outbound = nodes.find((n) => n.id === outboundId);

    const emptyW = NODE_WIDTH + GROUP_PADDING * 2;
    const emptyH = TITLE_HEIGHT + GROUP_PADDING * 2;
    const inboundW = (inbound?.style?.width as number) ?? emptyW;
    const inboundH = (inbound?.style?.height as number) ?? emptyH;
    const outboundW = (outbound?.style?.width as number) ?? emptyW;
    const outboundH = (outbound?.style?.height as number) ?? emptyH;

    // Position inbound subflow within its service group
    const inboundIdx = nodes.findIndex((n) => n.id === inboundId);
    if (inboundIdx !== -1) {
      nodes[inboundIdx] = {
        ...nodes[inboundIdx],
        position: { x: GROUP_PADDING, y: TITLE_HEIGHT + 15 },
      };
    }

    // Position outbound subflow below inbound
    const outboundIdx = nodes.findIndex((n) => n.id === outboundId);
    if (outboundIdx !== -1) {
      nodes[outboundIdx] = {
        ...nodes[outboundIdx],
        position: {
          x: GROUP_PADDING,
          y: TITLE_HEIGHT + 15 + inboundH + SUBGROUP_GAP,
        },
      };
    }

    // Stretch both subflows to the same width so they fill the service group
    const subflowW = Math.max(inboundW, outboundW);
    if (inboundIdx !== -1) {
      nodes[inboundIdx] = {
        ...nodes[inboundIdx],
        style: { ...nodes[inboundIdx].style, width: subflowW },
      };
      // Re-center inbound title
      const inboundTitleIdx = nodes.findIndex((n) => n.id === `${inboundId}-title`);
      if (inboundTitleIdx !== -1) {
        nodes[inboundTitleIdx] = {
          ...nodes[inboundTitleIdx],
          position: { x: subflowW / 2, y: 0 },
        };
      }
    }
    if (outboundIdx !== -1) {
      nodes[outboundIdx] = {
        ...nodes[outboundIdx],
        style: { ...nodes[outboundIdx].style, width: subflowW },
      };
      // Re-center outbound title
      const outboundTitleIdx = nodes.findIndex((n) => n.id === `${outboundId}-title`);
      if (outboundTitleIdx !== -1) {
        nodes[outboundTitleIdx] = {
          ...nodes[outboundTitleIdx],
          position: { x: subflowW / 2, y: 0 },
        };
      }
    }

    // Calculate service group size
    const serviceW = subflowW + GROUP_PADDING * 2;
    const serviceH =
      TITLE_HEIGHT + 15 + inboundH + SUBGROUP_GAP + outboundH + GROUP_PADDING;

    // Resize service group
    const serviceIdx = nodes.findIndex((n) => n.id === serviceGroup.id);
    if (serviceIdx !== -1) {
      nodes[serviceIdx] = {
        ...nodes[serviceIdx],
        style: { ...nodes[serviceIdx].style, width: serviceW, height: serviceH },
      };
    }

    // Center service title
    const titleId = `service-title${suffix}`;
    const titleIdx = nodes.findIndex((n) => n.id === titleId);
    if (titleIdx !== -1) {
      nodes[titleIdx] = {
        ...nodes[titleIdx],
        position: { x: serviceW / 2, y: 0 },
      };
    }

    serviceSizes.push({ w: serviceW, h: serviceH });
  }

  // Position service groups vertically (stacked)
  let serviceY = GROUP_PADDING;
  let maxServiceW = 0;

  for (let i = 0; i < sortedServices.length; i++) {
    const serviceIdx = nodes.findIndex((n) => n.id === sortedServices[i].id);
    if (serviceIdx !== -1) {
      nodes[serviceIdx] = {
        ...nodes[serviceIdx],
        position: { x: GROUP_PADDING, y: serviceY },
      };
    }
    maxServiceW = Math.max(maxServiceW, serviceSizes[i].w);
    serviceY += serviceSizes[i].h + GROUP_GAP;
  }

  // Position transport groups to the right of services, stacked vertically
  const transportX = GROUP_PADDING + maxServiceW + GROUP_GAP;
  let transportY = GROUP_PADDING;

  // Sort transports by ID for consistent ordering
  const sortedTransports = [...transportGroups].sort((a, b) =>
    a.id.localeCompare(b.id),
  );

  for (const transport of sortedTransports) {
    const transportIdx = nodes.findIndex((n) => n.id === transport.id);
    if (transportIdx !== -1) {
      nodes[transportIdx] = {
        ...nodes[transportIdx],
        position: { x: transportX, y: transportY },
      };

      const transportH = (nodes[transportIdx].style?.height as number) ?? 400;
      transportY += transportH + GROUP_GAP;
    }
  }
}

// =============================================================================
// CONVERT ELK LOCAL EDGE POINTS TO ABSOLUTE COORDINATES
// =============================================================================

/**
 * After positionGroups has placed transport groups at their final absolute
 * positions, convert the group-local ELK edge bendpoints to absolute
 * canvas coordinates and generate the final SVG path string.
 */
function applyAbsoluteEdgePaths(nodes: Node[], edges: Edge[]): void {
  // Build a map of group ID → absolute position
  const groupPositions = new Map<string, { x: number; y: number }>();
  for (const node of nodes) {
    if (node.type === "group") {
      groupPositions.set(node.id, node.position);
    }
  }

  for (let i = 0; i < edges.length; i++) {
    const edge = edges[i];
    const data = edge.data as Record<string, unknown> | undefined;
    if (!data?._elkLocalPoints || !data?._elkGroupId) continue;

    const localPoints = data._elkLocalPoints as Point[];
    const groupId = data._elkGroupId as string;
    const groupPos = groupPositions.get(groupId);
    if (!groupPos) continue;

    // Convert local points to absolute
    const absolutePoints: Point[] = localPoints.map((p) => ({
      x: p.x + groupPos.x,
      y: p.y + groupPos.y,
    }));

    // Generate SVG path with rounded corners
    const elkPath = generateSmoothStepPath(absolutePoints, 8);

    // Update edge with final path, remove temporary data
    // Store elkPoints so the edge component can re-anchor to actual handle positions
    const { _elkLocalPoints, _elkGroupId, ...cleanData } = data;
    edges[i] = {
      ...edge,
      data: { ...cleanData, elkPath, elkPoints: absolutePoints },
    };
  }
}

// =============================================================================
// POSITION SUMMARY NODES IN A COMPACT OVERVIEW LAYOUT
// =============================================================================

const SUMMARY_SERVICE_HEIGHT = 95;
const SUMMARY_TRANSPORT_HEIGHT = 90;
const SUMMARY_GAP = 40;
const SUMMARY_COLUMN_GAP = 160;

function positionSummaryNodes(nodes: Node[]): void {
  // Collect summary nodes by type
  const serviceSummaries: number[] = [];
  const transportSummaries: number[] = [];

  for (let i = 0; i < nodes.length; i++) {
    const node = nodes[i];
    if (node.type === "summaryService") serviceSummaries.push(i);
    else if (node.type === "summaryTransport") transportSummaries.push(i);
  }

  if (serviceSummaries.length === 0 && transportSummaries.length === 0) return;

  // Find the overall layout origin (top-left of all groups) as reference point
  let minX = Infinity;
  let minY = Infinity;
  for (const node of nodes) {
    if (node.type === "group") {
      minX = Math.min(minX, node.position.x);
      minY = Math.min(minY, node.position.y);
    }
  }
  if (!isFinite(minX)) minX = 0;
  if (!isFinite(minY)) minY = 0;

  // Position service summaries in a column on the left
  let serviceY = minY + GROUP_PADDING;
  for (const idx of serviceSummaries) {
    nodes[idx] = {
      ...nodes[idx],
      position: { x: minX + GROUP_PADDING, y: serviceY },
    };
    serviceY += SUMMARY_SERVICE_HEIGHT + SUMMARY_GAP;
  }

  // Position transport summaries in a column to the right of services
  const transportX = minX + GROUP_PADDING + 520 + SUMMARY_COLUMN_GAP;
  let transportY = minY + GROUP_PADDING;
  for (const idx of transportSummaries) {
    nodes[idx] = {
      ...nodes[idx],
      position: { x: transportX, y: transportY },
    };
    transportY += SUMMARY_TRANSPORT_HEIGHT + SUMMARY_GAP;
  }
}
