/**
 * =============================================================================
 * EDGE BUNDLING
 * =============================================================================
 *
 * This module implements metro-map style edge bundling for React Flow diagrams.
 * Instead of routing each edge independently (which causes overlaps), we:
 *
 * 1. IDENTIFY BUNDLES
 *    Group edges that share the same source and target "corridors"
 *    (e.g., all edges from service endpoints to transport entities)
 *
 * 2. ASSIGN LANES
 *    Within each bundle, assign a stable lane index to each edge
 *    Lane assignment is based on source/target Y positions for consistency
 *
 * 3. APPLY OFFSETS
 *    Each edge is offset perpendicular to its path based on its lane
 *    This creates parallel tracks like metro/subway maps
 *
 * VISUAL RESULT:
 * Before: Multiple edges taking identical paths, completely overlapping
 * After:  Parallel tracks with consistent spacing, easy to follow visually
 */

import type { Edge, Node } from "@xyflow/react";

// =============================================================================
// TYPES
// =============================================================================

export interface BundleInfo {
  /** Unique identifier for this bundle (based on corridor) */
  bundleId: string;
  /** This edge's lane index within the bundle (0-based) */
  laneIndex: number;
  /** Total number of lanes in this bundle */
  totalLanes: number;
  /** Offset in pixels for this lane (can be negative for centering) */
  laneOffset: number;
}

export interface BundledEdgeData {
  bundle?: BundleInfo;
  [key: string]: unknown;
}

// =============================================================================
// CONFIGURATION
// =============================================================================

const BUNDLE_CONFIG = {
  /** Spacing between parallel lanes in pixels */
  laneSpacing: 3,
  /** Minimum edges required to form a bundle (2 = only bundle when there are multiple edges) */
  minBundleSize: 2,
} as const;

// =============================================================================
// MAIN ENTRY POINT
// =============================================================================

/**
 * Analyzes edges and assigns bundle/lane information to each edge.
 *
 * @param edges - All edges in the diagram
 * @param nodes - All nodes in the diagram (used for position-based lane ordering)
 * @returns Edges with bundle information added to their data
 */
export function assignEdgeBundles(
  edges: Edge[],
  nodes: Node[],
): Edge<BundledEdgeData>[] {
  // Build a lookup for node positions
  const nodePositions = buildNodePositionMap(nodes);

  // Group edges into bundles by corridor
  const bundles = groupEdgesIntoBundles(edges, nodes);

  // Assign lane indices within each bundle
  const edgeLaneMap = assignLaneIndices(bundles, nodePositions);

  // Return edges with bundle info added to data
  return edges.map((edge) => {
    const bundleInfo = edgeLaneMap.get(edge.id);
    if (!bundleInfo) {
      return edge as Edge<BundledEdgeData>;
    }

    return {
      ...edge,
      data: {
        ...edge.data,
        bundle: bundleInfo,
      },
    } as Edge<BundledEdgeData>;
  });
}

// =============================================================================
// BUNDLE IDENTIFICATION
// =============================================================================

/**
 * Identifies the bundle key for an edge.
 *
 * BUNDLE STRATEGY:
 * Only edges that share the SAME SOURCE NODE are bundled together.
 * This creates a fan-out effect where multiple edges leaving the same
 * handle get slight offsets to prevent overlap.
 *
 * We don't bundle by target because edges going to different targets
 * will naturally diverge - no need to offset them.
 */
function getEdgeBundleKey(
  edge: Edge,
  _nodes: Node[],
): { bundleId: string } | null {
  // Bundle by source node - edges from the same source fan out
  const bundleId = `source:${edge.source}`;
  return { bundleId };
}

/**
 * Groups edges into bundles based on shared source node.
 */
function groupEdgesIntoBundles(
  edges: Edge[],
  nodes: Node[],
): Map<string, Edge[]> {
  const bundles = new Map<string, Edge[]>();

  for (const edge of edges) {
    const bundleKey = getEdgeBundleKey(edge, nodes);
    if (!bundleKey) continue;

    const existing = bundles.get(bundleKey.bundleId) || [];
    existing.push(edge);
    bundles.set(bundleKey.bundleId, existing);
  }

  return bundles;
}

// =============================================================================
// LANE ASSIGNMENT
// =============================================================================

interface NodePosition {
  x: number;
  y: number;
  centerY: number;
}

/**
 * Builds a map of node IDs to their positions.
 */
function buildNodePositionMap(nodes: Node[]): Map<string, NodePosition> {
  const positions = new Map<string, NodePosition>();

  for (const node of nodes) {
    const x = node.position.x;
    const y = node.position.y;
    const height = (node.measured?.height as number) ||
                   (node.style?.height as number) ||
                   40;

    positions.set(node.id, {
      x,
      y,
      centerY: y + height / 2,
    });
  }

  return positions;
}

/**
 * Assigns lane indices to edges within bundles.
 *
 * LANE ORDERING:
 * Edges are sorted by their source node's Y position, then target node's Y position.
 * This creates a stable, visually consistent ordering where edges don't cross
 * each other unnecessarily within the bundle.
 */
function assignLaneIndices(
  bundles: Map<string, Edge[]>,
  nodePositions: Map<string, NodePosition>,
): Map<string, BundleInfo> {
  const result = new Map<string, BundleInfo>();

  for (const [bundleId, bundleEdges] of bundles) {
    // Skip bundles that are too small
    if (bundleEdges.length < BUNDLE_CONFIG.minBundleSize) {
      continue;
    }

    // Sort edges by source Y, then target Y for consistent ordering
    const sortedEdges = [...bundleEdges].sort((a, b) => {
      const aSourcePos = nodePositions.get(a.source);
      const bSourcePos = nodePositions.get(b.source);
      const aTargetPos = nodePositions.get(a.target);
      const bTargetPos = nodePositions.get(b.target);

      // Primary sort: source Y position
      const sourceYDiff =
        (aSourcePos?.centerY ?? 0) - (bSourcePos?.centerY ?? 0);
      if (Math.abs(sourceYDiff) > 5) {
        return sourceYDiff;
      }

      // Secondary sort: target Y position
      return (aTargetPos?.centerY ?? 0) - (bTargetPos?.centerY ?? 0);
    });

    const totalLanes = sortedEdges.length;

    // Calculate offsets centered around 0
    // For 3 lanes: [-spacing, 0, +spacing]
    // For 4 lanes: [-1.5*spacing, -0.5*spacing, +0.5*spacing, +1.5*spacing]
    sortedEdges.forEach((edge, index) => {
      const laneOffset = calculateLaneOffset(index, totalLanes);

      result.set(edge.id, {
        bundleId,
        laneIndex: index,
        totalLanes,
        laneOffset,
      });
    });
  }

  return result;
}

/**
 * Calculates the perpendicular offset for a lane.
 * Offsets are centered around 0 so the bundle as a whole is centered.
 */
function calculateLaneOffset(laneIndex: number, totalLanes: number): number {
  if (totalLanes === 1) {
    return 0;
  }

  // Center the lanes around 0
  // For odd count: middle lane is at 0
  // For even count: lanes straddle 0
  const centerOffset = (totalLanes - 1) / 2;
  return (laneIndex - centerOffset) * BUNDLE_CONFIG.laneSpacing;
}

// =============================================================================
// UTILITY EXPORTS
// =============================================================================

/**
 * Gets the lane spacing configuration.
 * Useful for components that need to know the spacing.
 */
export function getLaneSpacing(): number {
  return BUNDLE_CONFIG.laneSpacing;
}

/**
 * Checks if an edge has bundle information.
 */
export function hasBundleInfo(edge: Edge<BundledEdgeData>): boolean {
  return edge.data?.bundle !== undefined;
}
