/**
 * =============================================================================
 * SMART EDGE PATHFINDING (OPTIMIZED)
 * =============================================================================
 *
 * High-performance A* pathfinding for routing edges around nodes.
 *
 * OPTIMIZATIONS:
 * - Binary heap priority queue: O(log n) insert/extract vs O(n) linear search
 * - Map-based open set tracking: O(1) lookup vs O(n) findIndex
 * - Larger grid cells (25px): Fewer nodes to explore
 * - Iteration limit: Prevents hanging on complex layouts
 * - Early termination: Simple paths skip A* entirely
 */

// =============================================================================
// TYPES
// =============================================================================

/** A 2D point in canvas coordinates */
export interface Point {
  x: number;
  y: number;
}

/**
 * Minimal node interface for pathfinding.
 */
export interface PathfindingNode {
  id: string;
  type?: string;
  position: { x: number; y: number };
  width?: number | null;
  height?: number | null;
}

/** Configuration for the pathfinding algorithm */
export interface PathfindingConfig {
  gridCellSize: number;
  nodePadding: number;
  borderRadius: number;
  graphPadding: number;
}

/** Bounding box for a rectangular region */
interface BoundingBox {
  minX: number;
  minY: number;
  maxX: number;
  maxY: number;
}

// =============================================================================
// DEFAULT CONFIGURATION
// =============================================================================

export const DEFAULT_CONFIG: PathfindingConfig = {
  gridCellSize: 25,    // Increased from 10 for better performance
  nodePadding: 10,
  borderRadius: 8,
  graphPadding: 20,
};

// Performance limits
const MAX_GRID_SIZE = 200;      // Max grid dimension (was 500)
const MAX_ITERATIONS = 5000;    // Max A* iterations before giving up

// =============================================================================
// BINARY HEAP (Priority Queue)
// =============================================================================

interface HeapNode {
  x: number;
  y: number;
  g: number;
  f: number;
  parentKey: string | null;
}

/**
 * Min-heap implementation for O(log n) priority queue operations.
 */
class MinHeap {
  private heap: HeapNode[] = [];
  private positionMap = new Map<string, number>(); // key -> heap index

  private key(x: number, y: number): string {
    return `${x},${y}`;
  }

  get size(): number {
    return this.heap.length;
  }

  push(node: HeapNode): void {
    const k = this.key(node.x, node.y);
    const existingIdx = this.positionMap.get(k);

    if (existingIdx !== undefined) {
      // Update existing node if new f is lower
      if (node.f < this.heap[existingIdx].f) {
        this.heap[existingIdx] = node;
        this.bubbleUp(existingIdx);
        this.bubbleDown(existingIdx);
      }
      return;
    }

    this.heap.push(node);
    this.positionMap.set(k, this.heap.length - 1);
    this.bubbleUp(this.heap.length - 1);
  }

  pop(): HeapNode | undefined {
    if (this.heap.length === 0) return undefined;

    const min = this.heap[0];
    const last = this.heap.pop()!;
    this.positionMap.delete(this.key(min.x, min.y));

    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.positionMap.set(this.key(last.x, last.y), 0);
      this.bubbleDown(0);
    }

    return min;
  }

  has(x: number, y: number): boolean {
    return this.positionMap.has(this.key(x, y));
  }

  private bubbleUp(idx: number): void {
    while (idx > 0) {
      const parentIdx = (idx - 1) >> 1;
      if (this.heap[idx].f >= this.heap[parentIdx].f) break;
      this.swap(idx, parentIdx);
      idx = parentIdx;
    }
  }

  private bubbleDown(idx: number): void {
    const length = this.heap.length;
    while (true) {
      const leftIdx = (idx << 1) + 1;
      const rightIdx = leftIdx + 1;
      let smallest = idx;

      if (leftIdx < length && this.heap[leftIdx].f < this.heap[smallest].f) {
        smallest = leftIdx;
      }
      if (rightIdx < length && this.heap[rightIdx].f < this.heap[smallest].f) {
        smallest = rightIdx;
      }
      if (smallest === idx) break;

      this.swap(idx, smallest);
      idx = smallest;
    }
  }

  private swap(i: number, j: number): void {
    const nodeI = this.heap[i];
    const nodeJ = this.heap[j];
    this.heap[i] = nodeJ;
    this.heap[j] = nodeI;
    this.positionMap.set(this.key(nodeI.x, nodeI.y), j);
    this.positionMap.set(this.key(nodeJ.x, nodeJ.y), i);
  }
}

// =============================================================================
// MAIN PATHFINDING FUNCTION
// =============================================================================

/**
 * Finds a path from source to target that avoids all obstacle nodes.
 */
export function findSmartPath(
  source: Point,
  target: Point,
  nodes: PathfindingNode[],
  config: PathfindingConfig = DEFAULT_CONFIG
): Point[] | null {
  // Filter out group nodes - they're containers, not obstacles
  const obstacleNodes = nodes.filter(
    (node) => node.type !== "group" && node.width && node.height
  );

  // OPTIMIZATION: Try simple orthogonal paths first
  const simplePath = trySimplePath(source, target, obstacleNodes, config);
  if (simplePath) {
    return simplePath;
  }

  // Calculate bounds
  const bounds = calculateBounds(source, target, obstacleNodes, config);

  // Create the pathfinding grid
  const grid = createGrid(bounds, obstacleNodes, config);
  if (!grid) return null;

  // Convert source and target to grid coordinates
  const startGrid = canvasToGrid(source, bounds, config.gridCellSize);
  const endGrid = canvasToGrid(target, bounds, config.gridCellSize);

  // Ensure valid positions
  if (!isValidGridPosition(startGrid, grid) || !isValidGridPosition(endGrid, grid)) {
    return null;
  }

  // Find nearest unblocked cells
  const adjustedStart = findNearestUnblockedCell(startGrid, grid);
  const adjustedEnd = findNearestUnblockedCell(endGrid, grid);

  if (!adjustedStart || !adjustedEnd) {
    return null;
  }

  // Run optimized A* pathfinding
  const gridPath = aStarSearchOptimized(adjustedStart, adjustedEnd, grid);

  if (!gridPath) {
    return null;
  }

  // Convert grid path back to canvas coordinates
  const canvasPath = gridPath.map((point) =>
    gridToCanvas(point, bounds, config.gridCellSize)
  );

  canvasPath.unshift(source);
  canvasPath.push(target);

  return simplifyPath(canvasPath);
}

// =============================================================================
// OPTIMIZED A* SEARCH
// =============================================================================

const DIRECTIONS = [
  { dx: 0, dy: -1 },
  { dx: 0, dy: 1 },
  { dx: -1, dy: 0 },
  { dx: 1, dy: 0 },
] as const;

function aStarSearchOptimized(
  start: Point,
  end: Point,
  grid: boolean[][]
): Point[] | null {
  const openSet = new MinHeap();
  const closedSet = new Set<string>();
  const cameFrom = new Map<string, string>();
  const gScores = new Map<string, number>();

  const key = (x: number, y: number) => `${x},${y}`;
  const startKey = key(start.x, start.y);
  const endKey = key(end.x, end.y);

  const h = (x: number, y: number) => Math.abs(x - end.x) + Math.abs(y - end.y);

  gScores.set(startKey, 0);
  openSet.push({
    x: start.x,
    y: start.y,
    g: 0,
    f: h(start.x, start.y),
    parentKey: null,
  });

  let iterations = 0;
  const gridHeight = grid.length;
  const gridWidth = grid[0].length;

  while (openSet.size > 0 && iterations < MAX_ITERATIONS) {
    iterations++;

    const current = openSet.pop()!;
    const currentKey = key(current.x, current.y);

    if (currentKey === endKey) {
      // Reconstruct path
      const path: Point[] = [];
      let k: string | undefined = currentKey;
      while (k) {
        const [x, y] = k.split(",").map(Number);
        path.unshift({ x, y });
        k = cameFrom.get(k);
      }
      return path;
    }

    closedSet.add(currentKey);

    for (const { dx, dy } of DIRECTIONS) {
      const nx = current.x + dx;
      const ny = current.y + dy;

      // Bounds check
      if (ny < 0 || ny >= gridHeight || nx < 0 || nx >= gridWidth) continue;

      // Skip blocked or already closed
      if (!grid[ny][nx]) continue;

      const neighborKey = key(nx, ny);
      if (closedSet.has(neighborKey)) continue;

      const tentativeG = current.g + 1;
      const existingG = gScores.get(neighborKey);

      if (existingG === undefined || tentativeG < existingG) {
        gScores.set(neighborKey, tentativeG);
        cameFrom.set(neighborKey, currentKey);

        openSet.push({
          x: nx,
          y: ny,
          g: tentativeG,
          f: tentativeG + h(nx, ny),
          parentKey: currentKey,
        });
      }
    }
  }

  return null;
}

// =============================================================================
// SIMPLE PATH STRATEGIES
// =============================================================================

function trySimplePath(
  source: Point,
  target: Point,
  obstacles: PathfindingNode[],
  config: PathfindingConfig
): Point[] | null {
  const midH: Point = { x: target.x, y: source.y };
  if (!pathIntersectsObstacles([source, midH, target], obstacles, config.nodePadding)) {
    return [source, midH, target];
  }

  const midV: Point = { x: source.x, y: target.y };
  if (!pathIntersectsObstacles([source, midV, target], obstacles, config.nodePadding)) {
    return [source, midV, target];
  }

  return null;
}

function pathIntersectsObstacles(
  path: Point[],
  obstacles: PathfindingNode[],
  padding: number
): boolean {
  for (let i = 0; i < path.length - 1; i++) {
    const p1 = path[i];
    const p2 = path[i + 1];

    for (const obs of obstacles) {
      if (lineIntersectsRect(p1, p2, obs, padding)) {
        return true;
      }
    }
  }
  return false;
}

function lineIntersectsRect(
  p1: Point,
  p2: Point,
  node: PathfindingNode,
  padding: number
): boolean {
  const left = node.position.x - padding;
  const right = node.position.x + (node.width ?? 0) + padding;
  const top = node.position.y - padding;
  const bottom = node.position.y + (node.height ?? 0) + padding;

  // Horizontal line
  if (p1.y === p2.y) {
    const y = p1.y;
    const minX = Math.min(p1.x, p2.x);
    const maxX = Math.max(p1.x, p2.x);
    return y >= top && y <= bottom && maxX >= left && minX <= right;
  }

  // Vertical line
  if (p1.x === p2.x) {
    const x = p1.x;
    const minY = Math.min(p1.y, p2.y);
    const maxY = Math.max(p1.y, p2.y);
    return x >= left && x <= right && maxY >= top && minY <= bottom;
  }

  // Diagonal - use Liang-Barsky
  return liangBarskyIntersection(p1, p2, { left, right, top, bottom });
}

function liangBarskyIntersection(
  p1: Point,
  p2: Point,
  rect: { left: number; right: number; top: number; bottom: number }
): boolean {
  const dx = p2.x - p1.x;
  const dy = p2.y - p1.y;
  const p = [-dx, dx, -dy, dy];
  const q = [p1.x - rect.left, rect.right - p1.x, p1.y - rect.top, rect.bottom - p1.y];

  let u1 = 0;
  let u2 = 1;

  for (let i = 0; i < 4; i++) {
    if (p[i] === 0) {
      if (q[i] < 0) return false;
    } else {
      const t = q[i] / p[i];
      if (p[i] < 0) u1 = Math.max(u1, t);
      else u2 = Math.min(u2, t);
    }
  }

  return u1 <= u2;
}

// =============================================================================
// GRID CREATION
// =============================================================================

function calculateBounds(
  source: Point,
  target: Point,
  nodes: PathfindingNode[],
  config: PathfindingConfig
): BoundingBox {
  let minX = Math.min(source.x, target.x);
  let minY = Math.min(source.y, target.y);
  let maxX = Math.max(source.x, target.x);
  let maxY = Math.max(source.y, target.y);

  for (const node of nodes) {
    minX = Math.min(minX, node.position.x);
    minY = Math.min(minY, node.position.y);
    maxX = Math.max(maxX, node.position.x + (node.width ?? 0));
    maxY = Math.max(maxY, node.position.y + (node.height ?? 0));
  }

  const padding = config.graphPadding + config.nodePadding;
  return {
    minX: minX - padding,
    minY: minY - padding,
    maxX: maxX + padding,
    maxY: maxY + padding,
  };
}

function createGrid(
  bounds: BoundingBox,
  nodes: PathfindingNode[],
  config: PathfindingConfig
): boolean[][] | null {
  let cellSize = config.gridCellSize;
  let width = Math.ceil((bounds.maxX - bounds.minX) / cellSize);
  let height = Math.ceil((bounds.maxY - bounds.minY) / cellSize);

  // Auto-scale cell size if grid too large
  if (width > MAX_GRID_SIZE || height > MAX_GRID_SIZE) {
    const scale = Math.max(width / MAX_GRID_SIZE, height / MAX_GRID_SIZE);
    cellSize = cellSize * scale;
    width = Math.ceil((bounds.maxX - bounds.minX) / cellSize);
    height = Math.ceil((bounds.maxY - bounds.minY) / cellSize);
  }

  // Still too large? Give up
  if (width > MAX_GRID_SIZE || height > MAX_GRID_SIZE) {
    return null;
  }

  // Initialize grid as walkable
  const grid: boolean[][] = Array.from({ length: height }, () =>
    Array(width).fill(true)
  );

  // Mark obstacles
  for (const node of nodes) {
    const nodeLeft = node.position.x - config.nodePadding;
    const nodeTop = node.position.y - config.nodePadding;
    const nodeRight = node.position.x + (node.width ?? 0) + config.nodePadding;
    const nodeBottom = node.position.y + (node.height ?? 0) + config.nodePadding;

    const startX = Math.max(0, Math.floor((nodeLeft - bounds.minX) / cellSize));
    const startY = Math.max(0, Math.floor((nodeTop - bounds.minY) / cellSize));
    const endX = Math.min(width, Math.ceil((nodeRight - bounds.minX) / cellSize));
    const endY = Math.min(height, Math.ceil((nodeBottom - bounds.minY) / cellSize));

    for (let y = startY; y < endY; y++) {
      for (let x = startX; x < endX; x++) {
        grid[y][x] = false;
      }
    }
  }

  return grid;
}

// =============================================================================
// COORDINATE CONVERSION
// =============================================================================

function canvasToGrid(point: Point, bounds: BoundingBox, cellSize: number): Point {
  return {
    x: Math.floor((point.x - bounds.minX) / cellSize),
    y: Math.floor((point.y - bounds.minY) / cellSize),
  };
}

function gridToCanvas(point: Point, bounds: BoundingBox, cellSize: number): Point {
  return {
    x: bounds.minX + (point.x + 0.5) * cellSize,
    y: bounds.minY + (point.y + 0.5) * cellSize,
  };
}

function isValidGridPosition(point: Point, grid: boolean[][]): boolean {
  return point.y >= 0 && point.y < grid.length && point.x >= 0 && point.x < grid[0].length;
}

function findNearestUnblockedCell(point: Point, grid: boolean[][]): Point | null {
  if (isValidGridPosition(point, grid) && grid[point.y][point.x]) {
    return point;
  }

  const visited = new Set<string>();
  const queue: Point[] = [point];

  while (queue.length > 0 && visited.size < 500) {
    const current = queue.shift()!;
    const key = `${current.x},${current.y}`;

    if (visited.has(key)) continue;
    visited.add(key);

    if (isValidGridPosition(current, grid) && grid[current.y][current.x]) {
      return current;
    }

    for (const { dx, dy } of DIRECTIONS) {
      queue.push({ x: current.x + dx, y: current.y + dy });
    }
  }

  return null;
}

// =============================================================================
// PATH SIMPLIFICATION
// =============================================================================

function simplifyPath(path: Point[]): Point[] {
  if (path.length <= 2) return path;

  const simplified: Point[] = [path[0]];

  for (let i = 1; i < path.length - 1; i++) {
    const prev = simplified[simplified.length - 1];
    const curr = path[i];
    const next = path[i + 1];

    const sameX = prev.x === curr.x && curr.x === next.x;
    const sameY = prev.y === curr.y && curr.y === next.y;

    if (!sameX && !sameY) {
      simplified.push(curr);
    }
  }

  simplified.push(path[path.length - 1]);
  return simplified;
}

// =============================================================================
// SVG PATH GENERATION
// =============================================================================

export function generateSmoothStepPath(
  points: Point[],
  borderRadius: number = 8
): string {
  if (points.length < 2) return "";

  let path = `M ${points[0].x},${points[0].y}`;

  for (let i = 1; i < points.length - 1; i++) {
    const prev = points[i - 1];
    const curr = points[i];
    const next = points[i + 1];

    const toPrev = { x: prev.x - curr.x, y: prev.y - curr.y };
    const toNext = { x: next.x - curr.x, y: next.y - curr.y };

    const lenToPrev = Math.sqrt(toPrev.x ** 2 + toPrev.y ** 2);
    const lenToNext = Math.sqrt(toNext.x ** 2 + toNext.y ** 2);

    const rounding = Math.min(borderRadius, lenToPrev / 2, lenToNext / 2);

    if (rounding > 0 && lenToPrev > 0 && lenToNext > 0) {
      const entryX = curr.x + (toPrev.x / lenToPrev) * rounding;
      const entryY = curr.y + (toPrev.y / lenToPrev) * rounding;
      const exitX = curr.x + (toNext.x / lenToNext) * rounding;
      const exitY = curr.y + (toNext.y / lenToNext) * rounding;

      path += ` L ${entryX},${entryY}`;
      path += ` Q ${curr.x},${curr.y} ${exitX},${exitY}`;
    } else {
      path += ` L ${curr.x},${curr.y}`;
    }
  }

  path += ` L ${points[points.length - 1].x},${points[points.length - 1].y}`;

  return path;
}

export function generateFallbackPath(source: Point, target: Point): string {
  const midX = (source.x + target.x) / 2;
  return `M ${source.x},${source.y} L ${midX},${source.y} L ${midX},${target.y} L ${target.x},${target.y}`;
}

// =============================================================================
// LANE OFFSET (for edge bundling)
// =============================================================================

export function applyLaneOffset(
  point: Point,
  handlePosition: "left" | "right" | "top" | "bottom",
  offset: number,
): Point {
  if (offset === 0) return point;

  switch (handlePosition) {
    case "left":
    case "right":
      return { x: point.x, y: point.y + offset };
    case "top":
    case "bottom":
      return { x: point.x + offset, y: point.y };
    default:
      return point;
  }
}
