/**
 * Search engine for topology entity search.
 *
 * Builds a flat search index from topology nodes for use by SearchPanel.
 */

import type { Node } from "@xyflow/react";
import type { CompactNodeData } from "../components/nodes/CompactNode";
import type { SimpleRouteNodeData } from "../components/nodes/SimpleRouteNode";

// =============================================================================
// SEARCH INDEX
// =============================================================================

export interface SearchableEntry {
  nodeId: string;
  label: string;
  description?: string;
  category: "consumer" | "saga" | "message" | "endpoint" | "entity" | "route";
  nodeType: string;
  subType?: string;
}

/**
 * Build a flat search index from topology nodes.
 * Produces per-node entries (no dedup by value), includes `entity-*` nodes,
 * and carries node IDs for navigation.
 */
export function buildSearchIndex(nodes: Node[]): SearchableEntry[] {
  const entries: SearchableEntry[] = [];

  for (const node of nodes) {
    const data = node.data as CompactNodeData | SimpleRouteNodeData;

    // Compact nodes (consumer, saga, message, endpoint, entity)
    if (node.type === "compact" && "nodeType" in data) {
      const compact = data as CompactNodeData;
      const fullData = compact.fullData;

      let description: string | undefined;
      if (fullData) {
        const identity = fullData.identity as string | undefined;
        const runtimeType = fullData.runtimeType as string | undefined;
        const name = fullData.name as string | undefined;
        description = runtimeType || identity || name;
      }

      const category = compact.nodeType as SearchableEntry["category"];
      entries.push({
        nodeId: node.id,
        label: compact.label,
        description: description !== compact.label ? description : undefined,
        category,
        nodeType: compact.nodeType,
        subType: compact.subType,
      });
    }

    // Route nodes
    if (node.type === "route" && "kind" in data) {
      const route = data as SimpleRouteNodeData;
      entries.push({
        nodeId: node.id,
        label: route.label,
        description: route.kind,
        category: "route",
        nodeType: "route",
        subType: route.direction,
      });
    }
  }

  return entries;
}
