/**
 * Zero-dependency fuzzy subsequence matcher with scoring.
 *
 * Returns a FuzzyResult with score and matched character indices,
 * or null if the query is not a subsequence of the target.
 */

export interface FuzzyResult {
  score: number;
  matchedIndices: number[];
}

/**
 * Fuzzy-match `query` against `target`.
 *
 * - Exact substring match gets highest score (~1000+).
 * - Subsequence matching with bonuses for consecutive chars, word
 *   boundaries (`.`, `-`, `_`, camelCase), early position, and
 *   length ratio.
 * - Case-insensitive.
 *
 * Returns `null` when the query is not a subsequence of the target.
 */
export function fuzzyMatch(
  query: string,
  target: string,
): FuzzyResult | null {
  if (query.length === 0) {
    return { score: 0, matchedIndices: [] };
  }

  const queryLower = query.toLowerCase();
  const targetLower = target.toLowerCase();

  // Fast exact-substring check
  const substringIndex = targetLower.indexOf(queryLower);
  if (substringIndex !== -1) {
    const indices: number[] = [];
    for (let i = 0; i < query.length; i++) {
      indices.push(substringIndex + i);
    }
    // Exact substring base score + bonuses
    let score = 1000 + query.length * 10;
    // Bonus for matching at the start
    if (substringIndex === 0) score += 100;
    // Bonus for length ratio (longer match relative to target = better)
    score += Math.round((query.length / target.length) * 50);
    return { score, matchedIndices: indices };
  }

  // Subsequence matching
  const matchedIndices: number[] = [];
  let qi = 0;

  for (let ti = 0; ti < target.length && qi < queryLower.length; ti++) {
    if (targetLower[ti] === queryLower[qi]) {
      matchedIndices.push(ti);
      qi++;
    }
  }

  // Not a full subsequence match
  if (qi !== queryLower.length) {
    return null;
  }

  // Score the subsequence match
  let score = 0;

  for (let i = 0; i < matchedIndices.length; i++) {
    const idx = matchedIndices[i];

    // Consecutive character bonus
    if (i > 0 && matchedIndices[i] === matchedIndices[i - 1] + 1) {
      score += 15;
    }

    // Word boundary bonus: char after `.`, `-`, `_`, or camelCase transition
    if (idx === 0) {
      score += 20; // start of string
    } else {
      const prev = target[idx - 1];
      const curr = target[idx];
      if (prev === "." || prev === "-" || prev === "_") {
        score += 20;
      } else if (
        prev === prev.toLowerCase() &&
        curr === curr.toUpperCase() &&
        curr !== curr.toLowerCase()
      ) {
        // camelCase boundary
        score += 15;
      }
    }

    // Early position bonus (first few characters matter more)
    score += Math.max(0, 10 - idx);
  }

  // Length ratio bonus
  score += Math.round((query.length / target.length) * 30);

  return { score, matchedIndices };
}
