/**
 * SearchPanel: Fuzzy search across all topology entities.
 *
 * Renders a search input with categorized fuzzy-match results.
 * Shows session-scoped recent searches when the query is empty.
 */

import { useState, useRef, useEffect, useMemo, useCallback } from "react";
import styled from "styled-components";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import {
  faGear,
  faDiagramProject,
  faEnvelope,
  faArrowRightArrowLeft,
  faCubes,
  faRoute,
  faClock,
  faXmark,
  faMagnifyingGlass,
} from "@fortawesome/free-solid-svg-icons";
import type { IconDefinition } from "@fortawesome/fontawesome-svg-core";
import { theme } from "../styles/theme";
import type { SearchableEntry } from "../utils/searchEngine";
import { fuzzyMatch } from "../utils/fuzzyMatch";

// =============================================================================
// PROPS
// =============================================================================

export interface SearchPanelProps {
  searchIndex: SearchableEntry[];
  onResultSelect: (nodeId: string) => void;
}

// =============================================================================
// CONSTANTS
// =============================================================================

const CATEGORY_ORDER: SearchableEntry["category"][] = [
  "consumer",
  "saga",
  "message",
  "endpoint",
  "entity",
  "route",
];

const CATEGORY_LABELS: Record<SearchableEntry["category"], string> = {
  consumer: "Consumers",
  saga: "Sagas",
  message: "Messages",
  endpoint: "Endpoints",
  entity: "Entities",
  route: "Routes",
};

const CATEGORY_ICONS: Record<SearchableEntry["category"], IconDefinition> = {
  consumer: faGear,
  saga: faDiagramProject,
  message: faEnvelope,
  endpoint: faArrowRightArrowLeft,
  entity: faCubes,
  route: faRoute,
};

const CATEGORY_COLORS: Record<SearchableEntry["category"], string> = {
  consumer: theme.colors.success.fg,
  saga: theme.colors.done.fg,
  message: theme.colors.attention.fg,
  endpoint: theme.colors.sponsors.fg,
  entity: theme.colors.scale.purple4,
  route: theme.colors.fg.muted,
};

const MAX_RESULTS = 50;
const MAX_RECENT = 10;

// =============================================================================
// COMPONENT
// =============================================================================

interface ScoredEntry {
  entry: SearchableEntry;
  score: number;
}

export function SearchPanel({ searchIndex, onResultSelect }: SearchPanelProps) {
  const [query, setQuery] = useState("");
  const [recentSearches, setRecentSearches] = useState<
    { label: string; nodeId: string; category: SearchableEntry["category"] }[]
  >([]);
  const inputRef = useRef<HTMLInputElement>(null);

  // Auto-focus input on mount
  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  // Compute fuzzy results
  const results = useMemo(() => {
    const trimmed = query.trim();
    if (trimmed.length === 0) return [];

    const scored: ScoredEntry[] = [];

    for (const entry of searchIndex) {
      const labelMatch = fuzzyMatch(trimmed, entry.label);
      const descMatch = entry.description
        ? fuzzyMatch(trimmed, entry.description)
        : null;

      const best = labelMatch && descMatch
        ? labelMatch.score >= descMatch.score
          ? labelMatch
          : descMatch
        : labelMatch ?? descMatch;

      if (best) {
        scored.push({ entry, score: best.score });
      }
    }

    // Sort by score descending
    scored.sort((a, b) => b.score - a.score);

    return scored.slice(0, MAX_RESULTS);
  }, [query, searchIndex]);

  // Group results by category
  const grouped = useMemo(() => {
    const groups = new Map<SearchableEntry["category"], ScoredEntry[]>();
    for (const item of results) {
      const list = groups.get(item.entry.category) ?? [];
      list.push(item);
      groups.set(item.entry.category, list);
    }
    return groups;
  }, [results]);

  const handleSelect = useCallback(
    (entry: SearchableEntry) => {
      onResultSelect(entry.nodeId);
      // Add to recent searches
      setRecentSearches((prev) => {
        const filtered = prev.filter((r) => r.nodeId !== entry.nodeId);
        return [
          { label: entry.label, nodeId: entry.nodeId, category: entry.category },
          ...filtered,
        ].slice(0, MAX_RECENT);
      });
    },
    [onResultSelect],
  );

  const handleClear = () => {
    setQuery("");
    inputRef.current?.focus();
  };

  const hasQuery = query.trim().length > 0;

  return (
    <PanelContainer>
      <SearchInputWrapper>
        <SearchPrefixIcon>
          <FontAwesomeIcon icon={faMagnifyingGlass} />
        </SearchPrefixIcon>
        <SearchInput
          ref={inputRef}
          type="text"
          placeholder="Search topology…"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          spellCheck={false}
          autoComplete="off"
        />
        {hasQuery && (
          <ClearButton onClick={handleClear} title="Clear search">
            <FontAwesomeIcon icon={faXmark} size="xs" />
          </ClearButton>
        )}
      </SearchInputWrapper>

      <ResultsContainer>
        {hasQuery && results.length === 0 && (
          <EmptyMessage>No results found</EmptyMessage>
        )}

        {hasQuery &&
          CATEGORY_ORDER.map((cat) => {
            const items = grouped.get(cat);
            if (!items || items.length === 0) return null;
            return (
              <CategoryGroup key={cat}>
                <CategoryHeader>
                  <CategoryIcon style={{ color: CATEGORY_COLORS[cat] }}>
                    <FontAwesomeIcon icon={CATEGORY_ICONS[cat]} />
                  </CategoryIcon>
                  <CategoryLabel>{CATEGORY_LABELS[cat]}</CategoryLabel>
                  <CategoryCount>{items.length}</CategoryCount>
                </CategoryHeader>
                {items.map(({ entry }) => (
                  <ResultRow
                    key={entry.nodeId}
                    onClick={() => handleSelect(entry)}
                  >
                    <ResultIcon style={{ color: CATEGORY_COLORS[entry.category] }}>
                      <FontAwesomeIcon icon={CATEGORY_ICONS[entry.category]} size="sm" />
                    </ResultIcon>
                    <ResultInfo>
                      <ResultLabel>{entry.label}</ResultLabel>
                      {entry.description && (
                        <ResultDescription>{entry.description}</ResultDescription>
                      )}
                    </ResultInfo>
                    <FocusLabel>Focus &rarr;</FocusLabel>
                  </ResultRow>
                ))}
              </CategoryGroup>
            );
          })}

        {!hasQuery && recentSearches.length > 0 && (
          <CategoryGroup>
            <CategoryHeader>
              <CategoryIcon style={{ color: theme.colors.fg.subtle }}>
                <FontAwesomeIcon icon={faClock} />
              </CategoryIcon>
              <CategoryLabel>Recent</CategoryLabel>
            </CategoryHeader>
            {recentSearches.map((recent) => (
              <ResultRow
                key={recent.nodeId}
                onClick={() => {
                  const entry = searchIndex.find(
                    (e) => e.nodeId === recent.nodeId,
                  );
                  if (entry) handleSelect(entry);
                  else onResultSelect(recent.nodeId);
                }}
              >
                <ResultIcon style={{ color: CATEGORY_COLORS[recent.category] }}>
                  <FontAwesomeIcon
                    icon={CATEGORY_ICONS[recent.category]}
                    size="sm"
                  />
                </ResultIcon>
                <ResultInfo>
                  <ResultLabel>{recent.label}</ResultLabel>
                </ResultInfo>
                <FocusLabel>Focus &rarr;</FocusLabel>
              </ResultRow>
            ))}
          </CategoryGroup>
        )}

        {!hasQuery && recentSearches.length === 0 && (
          <EmptyMessage>Type to search consumers, messages, endpoints…</EmptyMessage>
        )}
      </ResultsContainer>
    </PanelContainer>
  );
}

// =============================================================================
// STYLED COMPONENTS
// =============================================================================

