import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faServer, faNetworkWired } from '@fortawesome/free-solid-svg-icons';
import styled, { css } from 'styled-components';
import { theme } from '../../styles/theme';

export interface SimpleGroupLabelData {
  label: string;
  type: 'service' | 'transport';
  [key: string]: unknown;
}

const GroupLabelWrapper = styled.div`
  /* Position label to sit centered on the border line */
  /* translateX(-50%) centers horizontally, translateY(-50%) centers on border */
  transform: translate(-50%, -50%);
  pointer-events: none;
`;

const GroupLabelContainer = styled.div<{ $type: 'service' | 'transport' }>`
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 6px 14px;
  background: ${theme.colors.canvas.default};
  border: 1px solid ${theme.colors.border.default};
  border-radius: 6px;
  font-weight: 600;
  font-size: 13px;
  white-space: nowrap;

  ${props => props.$type === 'service' && css`
    background: ${theme.colors.canvas.default};
    border-color: ${theme.colors.border.default};
  `}

  ${props => props.$type === 'transport' && css`
    background: ${theme.colors.canvas.default};
    border-color: ${theme.colors.done.fg};
  `}
`;

const GroupLabelIcon = styled.span<{ $type: 'service' | 'transport' }>`
  font-size: 14px;
  color: ${props => props.$type === 'transport' 
    ? theme.colors.done.fg 
    : theme.colors.fg.muted};
`;

const GroupLabelText = styled.span`
  color: ${theme.colors.fg.default};
`;

export function SimpleGroupLabel({ data }: { data: SimpleGroupLabelData }) {
  const icon = data.type === 'service' ? faServer : faNetworkWired;

  return (
    <GroupLabelWrapper>
      <GroupLabelContainer $type={data.type}>
        <GroupLabelIcon $type={data.type}>
          <FontAwesomeIcon icon={icon} />
        </GroupLabelIcon>
        <GroupLabelText>{data.label}</GroupLabelText>
      </GroupLabelContainer>
    </GroupLabelWrapper>
  );
}
