/**
 * Lightweight edge component that renders a pre-computed SVG path from ELK.
 * No per-edge pathfinding - the path is computed once at layout time.
 *
 * When the rendered node dimensions differ from ELK-declared dimensions,
 * the first/last path points are re-anchored to the actual React Flow
 * handle positions so edges always connect to the visible node boundary.
 */

import { useMemo } from "react";
import { BaseEdge } from "@xyflow/react";
import { generateSmoothStepPath, type Point } from "../../utils/pathfinding";

export interface ElkRoutedEdgeData {
  /** Pre-computed SVG path string from ELK edge sections */
  elkPath?: string;
  /** Raw absolute points from ELK (start → bendpoints → end) */
  elkPoints?: Point[];
}

interface ElkRoutedEdgeProps {
  id: string;
  style?: React.CSSProperties;
  markerStart?: string;
  markerEnd?: string;
  data?: ElkRoutedEdgeData;
  sourceX: number;
  sourceY: number;
  targetX: number;
  targetY: number;
}

export function ElkRoutedEdge({
  id,
  style,
  markerStart,
  markerEnd,
  data,
  sourceX,
  sourceY,
  targetX,
  targetY,
}: ElkRoutedEdgeProps) {
  const path = useMemo(() => {
    const points = data?.elkPoints;
    if (!points || points.length < 2) {
      // No ELK routing data - straight line between handles
      return data?.elkPath ?? `M ${sourceX} ${sourceY} L ${targetX} ${targetY}`;
    }

    // Re-anchor start and end points to the actual React Flow handle positions.
    // ELK computes these based on declared node sizes which may differ from the
    // CSS-rendered sizes, causing edges to start/end in empty space.
    const first = points[0];
    const last = points[points.length - 1];

    const srcDx = Math.abs(first.x - sourceX);
    const srcDy = Math.abs(first.y - sourceY);
    const tgtDx = Math.abs(last.x - targetX);
    const tgtDy = Math.abs(last.y - targetY);

    // Only rebuild if there's a meaningful difference (> 2px) to avoid
    // unnecessary recalculation when dimensions match.
    const needsFix = srcDx > 2 || srcDy > 2 || tgtDx > 2 || tgtDy > 2;
    if (!needsFix) {
      return data?.elkPath ?? generateSmoothStepPath(points, 8);
    }

    // Clone and replace endpoints
    const adjusted = points.slice();
    adjusted[0] = { x: sourceX, y: sourceY };
    adjusted[adjusted.length - 1] = { x: targetX, y: targetY };

    return generateSmoothStepPath(adjusted, 8);
  }, [data, sourceX, sourceY, targetX, targetY]);

  return (
    <BaseEdge
      id={id}
      path={path}
      style={style}
      markerStart={markerStart}
      markerEnd={markerEnd}
    />
  );
}
